  1→//! macOS-native file copy using copyfile(3) API.
  2→//!
  3→//! This module provides FFI bindings for the macOS `copyfile` system call,
  4→//! which preserves extended attributes, ACLs, resource forks, and Finder metadata.
  5→//! It also supports APFS clonefile for instant copies on the same volume.
  6→
  7→use std::ffi::{CString, c_int, c_void};
  8→use std::path::Path;
  9→use std::sync::Arc;
 10→use std::sync::atomic::{AtomicBool, Ordering};
 11→
 12→use crate::file_system::write_operations::WriteOperationError;
 13→use crate::file_system::write_operations::types::IoResultExt;
 14→
 15→// ============================================================================
 16→// Type aliases for progress callbacks
 17→// ============================================================================
 18→
 19→/// Callback for progress updates (bytes copied for current file).
 20→type ProgressCallback = Box<dyn Fn(u64) + Send + Sync>;
 21→/// Callback when starting a new file.
 22→type FileStartCallback = Box<dyn Fn(&str) + Send + Sync>;
 23→/// Callback when finishing a file (with byte count).
 24→type FileFinishCallback = Box<dyn Fn(&str, u64) + Send + Sync>;
 25→
 26→// ============================================================================
 27→// FFI bindings for copyfile(3)
 28→// ============================================================================
 29→
 30→type CopyfileStateT = *mut c_void;
 31→type CopyfileFlagsT = u32;
 32→
 33→// copyfile flags from /usr/include/copyfile.h
 34→const COPYFILE_ACL: CopyfileFlagsT = 1 << 0;
 35→const COPYFILE_STAT: CopyfileFlagsT = 1 << 1;
 36→const COPYFILE_XATTR: CopyfileFlagsT = 1 << 2;
 37→const COPYFILE_DATA: CopyfileFlagsT = 1 << 3;
 38→const COPYFILE_ALL: CopyfileFlagsT = COPYFILE_ACL | COPYFILE_STAT | COPYFILE_XATTR | COPYFILE_DATA;
 39→const COPYFILE_RECURSIVE: CopyfileFlagsT = 1 << 15;
 40→const COPYFILE_EXCL: CopyfileFlagsT = 1 << 17;
 41→const COPYFILE_NOFOLLOW_SRC: CopyfileFlagsT = 1 << 18;
 42→const COPYFILE_CLONE: CopyfileFlagsT = 1 << 24;
 43→
 44→// copyfile_state constants
 45→const COPYFILE_STATE_STATUS_CB: c_int = 6;
 46→const COPYFILE_STATE_SRC_FILENAME: c_int = 1;
 47→const COPYFILE_STATE_DST_FILENAME: c_int = 2;
 48→const COPYFILE_STATE_COPIED: c_int = 8;
 49→const COPYFILE_STATE_STATUS_CTX: c_int = 7;
 50→
 51→// Progress callback return values
 52→const COPYFILE_CONTINUE: c_int = 0;
 53→const COPYFILE_QUIT: c_int = 1;
 54→
 55→// Progress callback what values
 56→const COPYFILE_RECURSE_FILE: c_int = 1;
 57→const COPYFILE_COPY_DATA: c_int = 4;
 58→
 59→// Progress callback stage values
 60→const COPYFILE_START: c_int = 1;
 61→const COPYFILE_FINISH: c_int = 2;
 62→const COPYFILE_PROGRESS: c_int = 4;
 63→
 64→#[link(name = "System", kind = "dylib")]
 65→unsafe extern "C" {
 66→    fn copyfile(from: *const i8, to: *const i8, state: CopyfileStateT, flags: CopyfileFlagsT) -> c_int;
 67→
 68→    fn copyfile_state_alloc() -> CopyfileStateT;
 69→    fn copyfile_state_free(state: CopyfileStateT) -> c_int;
 70→    fn copyfile_state_set(state: CopyfileStateT, flag: c_int, value: *const c_void) -> c_int;
 71→    fn copyfile_state_get(state: CopyfileStateT, flag: c_int, value: *mut c_void) -> c_int;
 72→}
 73→
 74→// ============================================================================
 75→// Progress callback types
 76→// ============================================================================
 77→
 78→/// Progress callback signature matching copyfile's expected type.
 79→type CopyfileCallback = extern "C" fn(
 80→    what: c_int,
 81→    stage: c_int,
 82→    state: CopyfileStateT,
 83→    src: *const i8,
 84→    dst: *const i8,
 85→    ctx: *mut c_void,
 86→) -> c_int;
 87→
 88→/// Context passed to the progress callback.
 89→pub struct CopyProgressContext {
 90→    /// Cancellation flag - checked during copy
 91→    pub cancelled: Arc<AtomicBool>,
 92→    /// Callback to report progress (bytes_copied for current file)
 93→    pub on_progress: Option<ProgressCallback>,
 94→    /// Callback when starting a new file
 95→    pub on_file_start: Option<FileStartCallback>,
 96→    /// Callback when finishing a file (with byte count)
 97→    pub on_file_finish: Option<FileFinishCallback>,
 98→}
 99→
100→impl Default for CopyProgressContext {
101→    fn default() -> Self {
102→        Self {
103→            cancelled: Arc::new(AtomicBool::new(false)),
104→            on_progress: None,
105→            on_file_start: None,
106→            on_file_finish: None,
107→        }
108→    }
109→}
110→
111→impl CopyProgressContext {
112→    /// Creates a context with only cancellation support (no callbacks).
113→    pub fn with_cancellation(cancelled: Arc<AtomicBool>) -> Self {
114→        Self {
115→            cancelled,
116→            on_progress: None,
117→            on_file_start: None,
118→            on_file_finish: None,
119→        }
120→    }
121→}
122→
123→/// The progress callback called by copyfile.
124→extern "C" fn copy_progress_callback(
125→    what: c_int,
126→    stage: c_int,
127→    state: CopyfileStateT,
128→    _src: *const i8,
129→    _dst: *const i8,
130→    ctx: *mut c_void,
131→) -> c_int {
132→    // Log callback invocation (helps diagnose if callback is being called at all)
133→    log::trace!(
134→        "copyfile callback: what={}, stage={}, ctx_null={}",
135→        what,
136→        stage,
137→        ctx.is_null()
138→    );
139→
140→    if ctx.is_null() {
141→        return COPYFILE_CONTINUE;
142→    }
143→
144→    // SAFETY: ctx is a pointer to CopyProgressContext that we passed in
145→    let context = unsafe { &*(ctx as *const CopyProgressContext) };
146→
147→    // Check cancellation
148→    if context.cancelled.load(Ordering::Relaxed) {
149→        log::info!("copyfile callback: cancellation detected, returning COPYFILE_QUIT");
150→        return COPYFILE_QUIT;
151→    }
152→
153→    match (what, stage) {
154→        // File copy started
155→        (COPYFILE_RECURSE_FILE, COPYFILE_START) | (COPYFILE_COPY_DATA, COPYFILE_START) => {
156→            if let Some(ref callback) = context.on_file_start {
157→                // Get source filename from state
158→                let mut src_ptr: *const i8 = std::ptr::null();
159→                unsafe {
160→                    copyfile_state_get(
161→                        state,
162→                        COPYFILE_STATE_SRC_FILENAME,
163→                        &mut src_ptr as *mut _ as *mut c_void,
164→                    );
165→                }
166→                if !src_ptr.is_null() {
167→                    let src_cstr = unsafe { std::ffi::CStr::from_ptr(src_ptr) };
168→                    if let Ok(src_str) = src_cstr.to_str() {
169→                        callback(src_str);
170→                    }
171→                }
172→            }
173→        }
174→
175→        // Progress during data copy
176→        (COPYFILE_COPY_DATA, COPYFILE_PROGRESS) => {
177→            if let Some(ref callback) = context.on_progress {
178→                let mut bytes_copied: i64 = 0;
179→                unsafe {
180→                    copyfile_state_get(state, COPYFILE_STATE_COPIED, &mut bytes_copied as *mut _ as *mut c_void);
181→                }
182→                callback(bytes_copied as u64);
183→            }
184→        }
185→
186→        // File copy finished
187→        (COPYFILE_RECURSE_FILE, COPYFILE_FINISH) | (COPYFILE_COPY_DATA, COPYFILE_FINISH) => {
188→            if let Some(ref callback) = context.on_file_finish {
189→                // Get destination filename and bytes copied
190→                let mut dst_ptr: *const i8 = std::ptr::null();
191→                let mut bytes_copied: i64 = 0;
192→                unsafe {
193→                    copyfile_state_get(
194→                        state,
195→                        COPYFILE_STATE_DST_FILENAME,
196→                        &mut dst_ptr as *mut _ as *mut c_void,
197→                    );
198→                    copyfile_state_get(state, COPYFILE_STATE_COPIED, &mut bytes_copied as *mut _ as *mut c_void);
199→                }
200→                if !dst_ptr.is_null() {
201→                    let dst_cstr = unsafe { std::ffi::CStr::from_ptr(dst_ptr) };
202→                    if let Ok(dst_str) = dst_cstr.to_str() {
203→                        callback(dst_str, bytes_copied as u64);
204→                    }
205→                }
206→            }
207→        }
208→
209→        _ => {}
210→    }
211→
212→    COPYFILE_CONTINUE
213→}
214→
215→// ============================================================================
216→// Public API
217→// ============================================================================
218→
219→/// Options for copy operations.
220→#[derive(Debug, Clone, Copy)]
221→pub struct CopyOptions {
222→    /// If true, fail if destination exists
223→    pub exclusive: bool,
224→    /// If true, copy directories recursively
225→    pub recursive: bool,
226→    /// If true, preserve symlinks (don't follow them)
227→    pub preserve_symlinks: bool,
228→}
229→
230→impl Default for CopyOptions {
231→    fn default() -> Self {
232→        Self {
233→            exclusive: false,
234→            recursive: true,
235→            preserve_symlinks: true,
236→        }
237→    }
238→}
239→
240→/// Copies a file or directory using macOS copyfile(3).
241→///
242→/// This preserves:
243→/// - Extended attributes (xattrs)
244→/// - ACLs
245→/// - Resource forks
246→/// - Finder metadata
247→/// - Uses clonefile on APFS for instant copies
248→///
249→/// # Arguments
250→/// * `source` - Source file or directory path
251→/// * `destination` - Destination path (will be created)
252→/// * `options` - Copy options
253→/// * `context` - Progress context for cancellation and callbacks (optional)
254→///
255→/// # Returns
256→/// * `Ok(())` on success
257→/// * `Err(WriteOperationError)` on failure
258→pub fn copy_file_native(
259→    source: &Path,
260→    destination: &Path,
261→    options: CopyOptions,
262→    context: Option<&CopyProgressContext>,
263→) -> Result<(), WriteOperationError> {
264→    let src_cstring = path_to_cstring(source)?;
265→    let dst_cstring = path_to_cstring(destination)?;
266→
267→    // Build flags
268→    let mut flags: CopyfileFlagsT = COPYFILE_ALL | COPYFILE_CLONE;
269→
270→    if options.preserve_symlinks {
271→        flags |= COPYFILE_NOFOLLOW_SRC;
272→    }
273→
274→    if options.exclusive {
275→        flags |= COPYFILE_EXCL;
276→    }
277→
278→    if options.recursive && source.is_dir() {
279→        flags |= COPYFILE_RECURSIVE;
280→    }
281→
282→    // If not exclusive and destination exists, remove it first
283→    // (copyfile doesn't have a built-in overwrite mode)
284→    if !options.exclusive && destination.exists() {
285→        if destination.is_dir() {
286→            std::fs::remove_dir_all(destination).map_err(|e| WriteOperationError::IoError {
287→                path: destination.display().to_string(),
288→                message: format!("Failed to remove existing destination: {}", e),
289→            })?;
290→        } else {
291→            std::fs::remove_file(destination).map_err(|e| WriteOperationError::IoError {
292→                path: destination.display().to_string(),
293→                message: format!("Failed to remove existing destination: {}", e),
294→            })?;
295→        }
296→    }
297→
298→    // Set up state for progress callbacks if context provided
299→    let state = unsafe { copyfile_state_alloc() };
300→    if state.is_null() {
301→        return Err(WriteOperationError::IoError {
302→            path: source.display().to_string(),
303→            message: "Failed to allocate copyfile state".to_string(),
304→        });
305→    }
306→
307→    // Set up progress callback if context provided
308→    if let Some(ctx) = context {
309→        unsafe {
310→            // Set callback function
311→            let callback_ptr = copy_progress_callback as CopyfileCallback as *const c_void;
312→            copyfile_state_set(state, COPYFILE_STATE_STATUS_CB, callback_ptr);
313→
314→            // Set context pointer
315→            let ctx_ptr = ctx as *const CopyProgressContext as *const c_void;
316→            copyfile_state_set(state, COPYFILE_STATE_STATUS_CTX, ctx_ptr);
317→        }
318→    }
319→
320→    // Perform the copy
321→    log::info!(
322→        "copyfile: starting copy from {} to {} (flags={:#x})",
323→        source.display(),
324→        destination.display(),
325→        flags
326→    );
327→    let result = unsafe { copyfile(src_cstring.as_ptr(), dst_cstring.as_ptr(), state, flags) };
328→    log::info!("copyfile: completed with result={}", result);
329→
330→    // Free state
331→    unsafe {
332→        copyfile_state_free(state);
333→    }
334→
335→    if result == 0 {
336→        Ok(())
337→    } else {
338→        // Check if cancelled
339→        if let Some(ctx) = context
340→            && ctx.cancelled.load(Ordering::Relaxed)
341→        {
342→            return Err(WriteOperationError::Cancelled {
343→                message: "Operation cancelled by user".to_string(),
344→            });
345→        }
346→
347→        // Get the actual error
348→        let err = std::io::Error::last_os_error();
349→        Err(map_io_error_with_path(err, source, destination))
350→    }
351→}
352→
353→/// Copies a single file using macOS copyfile(3) without recursive support.
354→/// This is more efficient for single files.
355→pub fn copy_single_file_native(
356→    source: &Path,
357→    destination: &Path,
358→    overwrite: bool,
359→    context: Option<&CopyProgressContext>,
360→) -> Result<u64, WriteOperationError> {
361→    let options = CopyOptions {
362→        exclusive: !overwrite,
363→        recursive: false,
364→        preserve_symlinks: true,
365→    };
366→
367→    copy_file_native(source, destination, options, context)?;
368→
369→    // Return the file size
370→    let metadata = std::fs::metadata(destination).with_path(destination)?;
371→
372→    Ok(metadata.len())
373→}
374→
375→/// Copies a symlink without following it.
376→pub fn copy_symlink(source: &Path, destination: &Path) -> Result<(), WriteOperationError> {
377→    let target = std::fs::read_link(source).map_err(|e| WriteOperationError::IoError {
378→        path: source.display().to_string(),
379→        message: format!("Failed to read symlink: {}", e),
380→    })?;
381→
382→    std::os::unix::fs::symlink(&target, destination).map_err(|e| WriteOperationError::IoError {
383→        path: destination.display().to_string(),
384→        message: format!("Failed to create symlink: {}", e),
385→    })?;
386→
387→    Ok(())
388→}
389→
390→// ============================================================================
391→// Helper functions
392→// ============================================================================
393→
394→/// Converts a Path to a CString for FFI.
395→fn path_to_cstring(path: &Path) -> Result<CString, WriteOperationError> {
396→    let path_str = path.to_str().ok_or_else(|| WriteOperationError::IoError {
397→        path: path.display().to_string(),
398→        message: "Path contains invalid UTF-8".to_string(),
399→    })?;
400→
401→    CString::new(path_str).map_err(|_| WriteOperationError::IoError {
402→        path: path.display().to_string(),
403→        message: "Path contains null byte".to_string(),
404→    })
405→}
406→
407→/// Maps an IO error to a WriteOperationError with path context.
408→fn map_io_error_with_path(err: std::io::Error, source: &Path, destination: &Path) -> WriteOperationError {
409→    match err.kind() {
410→        std::io::ErrorKind::NotFound => WriteOperationError::SourceNotFound {
411→            path: source.display().to_string(),
412→        },
413→        std::io::ErrorKind::PermissionDenied => WriteOperationError::PermissionDenied {
414→            path: destination.display().to_string(),
415→            message: format!("Cannot write to {}: permission denied", destination.display()),
416→        },
417→        std::io::ErrorKind::AlreadyExists => WriteOperationError::DestinationExists {
418→            path: destination.display().to_string(),
419→        },
420→        _ => {
421→            // Check for disk full (ENOSPC = 28 on macOS)
422→            if let Some(os_err) = err.raw_os_error()
423→                && os_err == 28
424→            {
425→                // ENOSPC - we don't have exact space info here, so use 0
426→                return WriteOperationError::InsufficientSpace {
427→                    required: 0,
428→                    available: 0,
429→                    volume_name: None,
430→                };
431→            }
432→            WriteOperationError::IoError {
433→                path: source.display().to_string(),
434→                message: err.to_string(),
435→            }
436→        }
437→    }
438→}
