444→#[cfg(test)]
445→mod tests {
446→    use super::*;
447→    use std::fs;
448→    use std::os::unix::fs::PermissionsExt;
449→
450→    fn create_temp_dir(name: &str) -> std::path::PathBuf {
451→        let temp_dir = std::env::temp_dir().join(format!("cmdr_macos_copy_test_{}", name));
452→        let _ = fs::remove_dir_all(&temp_dir);
453→        fs::create_dir_all(&temp_dir).expect("Failed to create temp directory");
454→        temp_dir
455→    }
456→
457→    fn cleanup_temp_dir(path: &std::path::PathBuf) {
458→        let _ = fs::remove_dir_all(path);
459→    }
460→
461→    #[test]
462→    fn test_copy_single_file() {
463→        let temp_dir = create_temp_dir("single_file");
464→        let src = temp_dir.join("source.txt");
465→        let dst = temp_dir.join("dest.txt");
466→
467→        fs::write(&src, "Hello, world!").unwrap();
468→
469→        let result = copy_single_file_native(&src, &dst, false, None);
470→        assert!(result.is_ok());
471→        assert!(dst.exists());
472→        assert_eq!(fs::read_to_string(&dst).unwrap(), "Hello, world!");
473→
474→        cleanup_temp_dir(&temp_dir);
475→    }
476→
477→    #[test]
478→    fn test_copy_preserves_permissions() {
479→        let temp_dir = create_temp_dir("permissions");
480→        let src = temp_dir.join("source.sh");
481→        let dst = temp_dir.join("dest.sh");
482→
483→        fs::write(&src, "#!/bin/bash\necho hello").unwrap();
484→        fs::set_permissions(&src, fs::Permissions::from_mode(0o755)).unwrap();
485→
486→        let result = copy_single_file_native(&src, &dst, false, None);
487→        assert!(result.is_ok());
488→
489→        let dst_perms = fs::metadata(&dst).unwrap().permissions().mode();
490→        // Check executable bits are preserved (mask with 0o777 to ignore file type bits)
491→        assert_eq!(dst_perms & 0o777, 0o755);
492→
493→        cleanup_temp_dir(&temp_dir);
494→    }
495→
496→    #[test]
497→    fn test_copy_symlink() {
498→        let temp_dir = create_temp_dir("symlink");
499→        let target = temp_dir.join("target.txt");
500→        let src_link = temp_dir.join("source_link");
501→        let dst_link = temp_dir.join("dest_link");
502→
503→        fs::write(&target, "target content").unwrap();
504→        std::os::unix::fs::symlink(&target, &src_link).unwrap();
505→
506→        let result = copy_symlink(&src_link, &dst_link);
507→        assert!(result.is_ok());
508→
509→        // Verify it's a symlink, not a regular file
510→        assert!(dst_link.is_symlink());
511→        let link_target = fs::read_link(&dst_link).unwrap();
512→        assert_eq!(link_target, target);
513→
514→        cleanup_temp_dir(&temp_dir);
515→    }
516→
517→    #[test]
518→    fn test_copy_broken_symlink() {
519→        let temp_dir = create_temp_dir("broken_symlink");
520→        let nonexistent = temp_dir.join("nonexistent");
521→        let src_link = temp_dir.join("broken_link");
522→        let dst_link = temp_dir.join("dest_broken_link");
523→
524→        // Create a symlink to a nonexistent target
525→        std::os::unix::fs::symlink(&nonexistent, &src_link).unwrap();
526→
527→        let result = copy_symlink(&src_link, &dst_link);
528→        assert!(result.is_ok());
529→
530→        // Verify it's a broken symlink
531→        assert!(dst_link.is_symlink());
532→        assert!(!dst_link.exists()); // exists() returns false for broken symlinks
533→
534→        cleanup_temp_dir(&temp_dir);
535→    }
536→
537→    #[test]
538→    fn test_copy_fails_on_existing_exclusive() {
539→        let temp_dir = create_temp_dir("exclusive");
540→        let src = temp_dir.join("source.txt");
541→        let dst = temp_dir.join("dest.txt");
542→
543→        fs::write(&src, "source").unwrap();
544→        fs::write(&dst, "existing").unwrap();
545→
546→        // Should fail with exclusive = true (overwrite = false)
547→        let result = copy_single_file_native(&src, &dst, false, None);
548→        assert!(result.is_err());
549→
550→        // Original content should be preserved
551→        assert_eq!(fs::read_to_string(&dst).unwrap(), "existing");
552→
553→        cleanup_temp_dir(&temp_dir);
554→    }
555→
556→    #[test]
557→    fn test_copy_overwrites_when_allowed() {
558→        let temp_dir = create_temp_dir("overwrite");
559→        let src = temp_dir.join("source.txt");
560→        let dst = temp_dir.join("dest.txt");
561→
562→        fs::write(&src, "new content").unwrap();
563→        fs::write(&dst, "old content").unwrap();
564→
565→        let result = copy_single_file_native(&src, &dst, true, None);
566→        assert!(result.is_ok());
567→        assert_eq!(fs::read_to_string(&dst).unwrap(), "new content");
568→
569→        cleanup_temp_dir(&temp_dir);
570→    }
571→
572→    #[test]
573→    fn test_copy_directory_recursive() {
574→        let temp_dir = create_temp_dir("recursive");
575→        let src_dir = temp_dir.join("source_dir");
576→        let dst_dir = temp_dir.join("dest_dir");
577→
578→        // Create nested structure
579→        fs::create_dir_all(src_dir.join("subdir")).unwrap();
580→        fs::write(src_dir.join("file1.txt"), "file1").unwrap();
581→        fs::write(src_dir.join("subdir/file2.txt"), "file2").unwrap();
582→
583→        let options = CopyOptions::default();
584→        let result = copy_file_native(&src_dir, &dst_dir, options, None);
585→        assert!(result.is_ok());
586→
587→        assert!(dst_dir.join("file1.txt").exists());
588→        assert!(dst_dir.join("subdir/file2.txt").exists());
589→        assert_eq!(fs::read_to_string(dst_dir.join("file1.txt")).unwrap(), "file1");
590→        assert_eq!(fs::read_to_string(dst_dir.join("subdir/file2.txt")).unwrap(), "file2");
591→
592→        cleanup_temp_dir(&temp_dir);
593→    }
594→
595→    #[test]
596→    fn test_cancellation() {
597→        let temp_dir = create_temp_dir("cancellation");
598→        let src = temp_dir.join("source.txt");
599→        let dst = temp_dir.join("dest.txt");
600→
601→        fs::write(&src, "content").unwrap();
602→
603→        let context = CopyProgressContext::with_cancellation(Arc::new(AtomicBool::new(true))); // Pre-cancelled
604→
605→        let _result = copy_single_file_native(&src, &dst, false, Some(&context));
606→        // Note: cancellation is checked in the callback, so for small files it may complete
607→        // before the callback runs. This test verifies the mechanism exists.
608→
609→        cleanup_temp_dir(&temp_dir);
610→    }
611→}
