  1→//! Copy implementation for write operations.
  2→
  3→use std::collections::HashSet;
  4→use std::fs;
  5→use std::path::{Path, PathBuf};
  6→use std::sync::Arc;
  7→use std::sync::atomic::Ordering;
  8→use std::time::{Duration, Instant};
  9→
 10→#[cfg(target_os = "macos")]
