 28→
 29→/// Runs `validate_disk_space` with polling-based cancellation.
 30→/// This ensures we respond quickly to cancellation even if `statvfs` blocks on slow network drives.
 31→fn validate_disk_space_cancellable(
 32→    destination: &Path,
 33→    required_bytes: u64,
 34→    state: &Arc<WriteOperationState>,
 35→    operation_id: &str,
 36→) -> Result<(), WriteOperationError> {
 37→    let destination = destination.to_path_buf();
 38→    run_cancellable(
 39→        move || validate_disk_space(&destination, required_bytes),
 40→        state,
 41→        "disk_space_check",
 42→        operation_id,
 43→    )
 44→}
