 49→
 50→pub(super) fn copy_files_with_progress(
 51→    app: &tauri::AppHandle,
 52→    operation_id: &str,
 53→    state: &Arc<WriteOperationState>,
 54→    sources: &[PathBuf],
 55→    destination: &Path,
 56→    config: &WriteOperationConfig,
 57→) -> Result<(), WriteOperationError> {
 58→    use tauri::Emitter;
 59→
 60→    log::debug!(
 61→        "copy_files_with_progress: starting operation_id={}, {} sources",
 62→        operation_id,
 63→        sources.len()
 64→    );
 65→
 66→    // Handle dry-run mode
 67→    if handle_dry_run(
 68→        config.dry_run,
 69→        sources,
 70→        destination,
 71→        state,
 72→        app,
 73→        operation_id,
 74→        WriteOperationType::Copy,
 75→        state.progress_interval,
 76→        config.max_conflicts_to_show,
 77→    )? {
 78→        return Ok(());
 79→    }
 80→
 81→    // Phase 1: Scan (or reuse cached preview results)
 82→    let scan_result = if let Some(preview_id) = &config.preview_id {
 83→        // Try to reuse cached scan results from preview
 84→        if let Some(cached) = take_cached_scan_result(preview_id) {
 85→            log::info!(
 86→                "copy_files_with_progress: reusing cached scan for operation_id={}, preview_id={}, files={}, bytes={}",
 87→                operation_id,
 88→                preview_id,
 89→                cached.file_count,
 90→                cached.total_bytes
 91→            );
 92→            cached
 93→        } else {
 94→            // Cache miss or expired, do normal scan
 95→            log::debug!(
 96→                "copy_files_with_progress: preview_id={} cache miss, starting fresh scan for operation_id={}",
 97→                preview_id,
 98→                operation_id
 99→            );
100→            scan_sources(
101→                sources,
102→                state,
103→                app,
104→                operation_id,
105→                WriteOperationType::Copy,
106→                config.sort_column,
107→                config.sort_order,
108→            )?
109→        }
110→    } else {
111→        // No preview ID, do normal scan
112→        log::debug!(
113→            "copy_files_with_progress: starting scan phase for operation_id={}",
114→            operation_id
115→        );
116→        scan_sources(
117→            sources,
118→            state,
119→            app,
120→            operation_id,
121→            WriteOperationType::Copy,
122→            config.sort_column,
123→            config.sort_order,
124→        )?
125→    };
126→    log::info!(
127→        "copy_files_with_progress: scan complete for operation_id={}, files={}, bytes={}",
128→        operation_id,
129→        scan_result.file_count,
130→        scan_result.total_bytes
131→    );
132→
133→    // Pre-flight disk space check: verify destination has enough free space
134→    // Use polling-based cancellation to remain responsive on slow network drives
135→    log::info!(
136→        "copy_files_with_progress: starting disk space check for operation_id={}",
137→        operation_id
138→    );
139→    validate_disk_space_cancellable(destination, scan_result.total_bytes, state, operation_id)?;
140→    log::info!(
141→        "copy_files_with_progress: disk space check complete for operation_id={}",
142→        operation_id
143→    );
144→
145→    // Phase 2: Copy files in sorted order with rollback support
146→    let mut transaction = CopyTransaction::new();
147→    let mut files_done = 0;
148→    let mut bytes_done = 0u64;
149→    let mut last_progress_time = Instant::now();
150→    let mut apply_to_all_resolution: Option<ConflictResolution> = None;
151→    let mut created_dirs: HashSet<PathBuf> = HashSet::new();
152→
153→    // Emit initial copying phase event (important when reusing cached scan - no scanning events were emitted)
154→    let _ = app.emit(
155→        "write-progress",
156→        WriteProgressEvent {
157→            operation_id: operation_id.to_string(),
158→            operation_type: WriteOperationType::Copy,
159→            phase: WriteOperationPhase::Copying,
160→            current_file: None,
161→            files_done: 0,
162→            files_total: scan_result.file_count,
163→            bytes_done: 0,
164→            bytes_total: scan_result.total_bytes,
165→        },
166→    );
167→    update_operation_status(
168→        operation_id,
169→        WriteOperationPhase::Copying,
170→        None,
171→        0,
172→        scan_result.file_count,
173→        0,
174→        scan_result.total_bytes,
175→    );
176→
177→    log::info!(
178→        "copy_files_with_progress: starting copy loop for operation_id={}, {} files",
179→        operation_id,
180→        scan_result.files.len()
181→    );
182→
183→    let mut tracker = SourceItemTracker::new(&scan_result.files);
184→
185→    let result: Result<(), WriteOperationError> = (|| {
186→        for file_info in &scan_result.files {
187→            log::debug!(
188→                "copy_files_with_progress: copying file {} ({} bytes)",
189→                file_info.path.display(),
190→                file_info.size
191→            );
192→            copy_single_item(
193→                &file_info.path,
194→                file_info.dest_path(destination),
195→                file_info.is_symlink,
196→                &mut files_done,
197→                &mut bytes_done,
198→                scan_result.file_count,
199→                scan_result.total_bytes,
200→                state,
201→                app,
202→                operation_id,
203→                WriteOperationType::Copy,
204→                &state.progress_interval,
205→                &mut last_progress_time,
206→                config,
207→                &mut transaction,
208→                &mut apply_to_all_resolution,
209→                &mut created_dirs,
210→            )?;
211→
212→            if let Some(source_path) = tracker.record(file_info) {
213→                let _ = app.emit(
214→                    "write-source-item-done",
215→                    WriteSourceItemDoneEvent {
216→                        operation_id: operation_id.to_string(),
217→                        source_path: source_path.display().to_string(),
218→                    },
219→                );
220→            }
221→        }
222→        Ok(())
223→    })();
224→
225→    match result {
226→        Ok(()) => {
227→            // Success - commit transaction (don't rollback)
228→            transaction.commit();
229→
230→            // Spawn async sync for durability (non-blocking)
231→            spawn_async_sync();
232→
233→            log::info!(
234→                "copy_files_with_progress: completed op={} files={} bytes={}",
235→                operation_id,
236→                files_done,
237→                bytes_done
238→            );
239→
240→            // Emit completion
241→            let _ = app.emit(
242→                "write-complete",
243→                WriteCompleteEvent {
244→                    operation_id: operation_id.to_string(),
245→                    operation_type: WriteOperationType::Copy,
246→                    files_processed: files_done,
247→                    bytes_processed: bytes_done,
248→                },
249→            );
250→            Ok(())
251→        }
252→        Err(e) => {
253→            if matches!(e, WriteOperationError::Cancelled { .. }) {
254→                // Cancellation - check if user wants to keep partial files
255→                let skip_rollback = state.skip_rollback.load(Ordering::Relaxed);
256→                let rolled_back = !skip_rollback;
257→
258→                if skip_rollback {
259→                    log::info!(
260→                        "copy_files_with_progress: cancelled op={}, keeping {} partial files",
261→                        operation_id,
262→                        transaction.created_files.len()
263→                    );
264→                    transaction.commit();
265→                } else {
266→                    log::info!(
267→                        "copy_files_with_progress: cancelled op={}, rolling back {} files",
268→                        operation_id,
269→                        transaction.created_files.len()
270→                    );
271→                    transaction.rollback();
272→                }
273→
274→                let _ = app.emit(
275→                    "write-cancelled",
276→                    WriteCancelledEvent {
277→                        operation_id: operation_id.to_string(),
278→                        operation_type: WriteOperationType::Copy,
279→                        files_processed: files_done,
280→                        rolled_back,
281→                    },
282→                );
283→            } else {
284→                // Non-cancellation error - always rollback
285→                log::error!(
286→                    "copy_files_with_progress: failed op={} error={:?}, rolling back",
287→                    operation_id,
288→                    e
289→                );
290→                transaction.rollback();
291→
292→                let _ = app.emit(
293→                    "write-error",
294→                    WriteErrorEvent {
295→                        operation_id: operation_id.to_string(),
296→                        operation_type: WriteOperationType::Copy,
297→                        error: e.clone(),
298→                    },
299→                );
300→            }
301→            Err(e)
302→        }
303→    }
304→}
