306→/// Copies a single file or symlink to its destination.
307→/// Ensures parent directories exist before copying.
308→/// Used by both copy and cross-filesystem move operations.
309→#[allow(
310→    clippy::too_many_arguments,
311→    reason = "File copy requires passing state through multiple levels"
312→)]
313→pub(super) fn copy_single_item(
314→    source: &Path,
315→    dest_path: PathBuf,
316→    is_symlink: bool,
317→    files_done: &mut usize,
318→    bytes_done: &mut u64,
319→    files_total: usize,
320→    bytes_total: u64,
321→    state: &Arc<WriteOperationState>,
322→    app: &tauri::AppHandle,
323→    operation_id: &str,
324→    operation_type: WriteOperationType,
325→    progress_interval: &Duration,
326→    last_progress_time: &mut Instant,
327→    config: &WriteOperationConfig,
328→    transaction: &mut CopyTransaction,
329→    apply_to_all_resolution: &mut Option<ConflictResolution>,
330→    created_dirs: &mut HashSet<PathBuf>,
331→) -> Result<(), WriteOperationError> {
332→    use tauri::Emitter;
333→
334→    // Check cancellation
335→    if state.cancelled.load(Ordering::Relaxed) {
336→        log::debug!(
337→            "copy: cancellation detected op={} files_done={}",
338→            operation_id,
339→            *files_done
340→        );
341→        return Err(WriteOperationError::Cancelled {
342→            message: "Operation cancelled by user".to_string(),
343→        });
344→    }
345→
346→    // Ensure parent directories exist
347→    if let Some(parent) = dest_path.parent()
348→        && !created_dirs.contains(parent)
349→        && !parent.exists()
350→    {
351→        // Collect directories that don't exist BEFORE creating them
352→        // (so we know exactly which ones we're creating for rollback)
353→        let mut dirs_to_create: Vec<PathBuf> = Vec::new();
354→        let mut dir = parent.to_path_buf();
355→        while !dir.exists() && !created_dirs.contains(&dir) {
356→            dirs_to_create.push(dir.clone());
357→            match dir.parent() {
358→                Some(p) => dir = p.to_path_buf(),
359→                None => break,
360→            }
361→        }
362→
363→        // Create all directories
364→        fs::create_dir_all(parent).map_err(|e| WriteOperationError::IoError {
365→            path: parent.display().to_string(),
366→            message: format!("Failed to create directory: {}", e),
367→        })?;
368→
369→        // Record only the directories we actually created (in creation order: deepest last)
370→        // dirs_to_create is in reverse order (deepest first), so iterate in reverse
371→        for created_dir in dirs_to_create.into_iter().rev() {
372→            transaction.record_dir(created_dir.clone());
373→            created_dirs.insert(created_dir);
374→        }
375→    }
376→
377→    // Get metadata for size tracking
378→    let metadata = fs::symlink_metadata(source).with_path(source)?;
379→
380→    let file_name = source.file_name().unwrap_or_default();
381→
382→    if is_symlink {
383→        // Handle symlink
384→        let (actual_dest, needs_safe_overwrite) = if dest_path.exists() || fs::symlink_metadata(&dest_path).is_ok() {
385→            match resolve_conflict(
386→                source,
387→                &dest_path,
388→                config,
389→                app,
390→                operation_id,
391→                state,
392→                apply_to_all_resolution,
393→            )? {
394→                Some(resolved) => (resolved.path, resolved.needs_safe_overwrite),
395→                None => {
396→                    // Skip this file but still count it toward progress
397→                    *files_done += 1;
398→                    *bytes_done += metadata.len();
399→                    return Ok(());
400→                }
401→            }
402→        } else {
403→            (dest_path.clone(), false)
404→        };
405→
406→        // Validate destination path length limits
407→        validate_path_length(&actual_dest)?;
408→
409→        if needs_safe_overwrite {
410→            if actual_dest.is_dir() {
411→                fs::remove_dir_all(&actual_dest).with_path(&actual_dest)?;
412→            } else {
413→                fs::remove_file(&actual_dest).with_path(&actual_dest)?;
414→            }
415→        }
416→
417→        #[cfg(target_os = "macos")]
418→        {
419→            copy_symlink(source, &actual_dest)?;
420→        }
421→        #[cfg(not(target_os = "macos"))]
422→        {
423→            let target = fs::read_link(source).map_err(|e| WriteOperationError::IoError {
424→                path: source.display().to_string(),
425→                message: format!("Failed to read symlink: {}", e),
426→            })?;
427→            std::os::unix::fs::symlink(&target, &actual_dest).map_err(|e| WriteOperationError::IoError {
428→                path: actual_dest.display().to_string(),
429→                message: format!("Failed to create symlink: {}", e),
430→            })?;
431→        }
432→
433→        transaction.record_file(actual_dest);
434→        *files_done += 1;
435→        *bytes_done += metadata.len();
436→    } else {
437→        // Handle regular file
438→        let (actual_dest, needs_safe_overwrite) = if dest_path.exists() {
439→            match resolve_conflict(
440→                source,
441→                &dest_path,
442→                config,
443→                app,
444→                operation_id,
445→                state,
446→                apply_to_all_resolution,
447→            )? {
448→                Some(resolved) => (resolved.path, resolved.needs_safe_overwrite),
449→                None => {
450→                    // Skip this file but still count it toward progress
451→                    *files_done += 1;
452→                    *bytes_done += metadata.len();
453→                    return Ok(());
454→                }
455→            }
456→        } else {
457→            (dest_path.clone(), false)
458→        };
459→
460→        // Validate destination path length limits
461→        validate_path_length(&actual_dest)?;
462→
463→        // Prevent copying a file over itself via symlinks (same inode + device)
464→        if is_same_file(source, &actual_dest) {
465→            log::warn!(
466→                "copy: skipping {}: source and destination resolve to the same file",
467→                source.display()
468→            );
469→            *files_done += 1;
470→            *bytes_done += metadata.len();
471→            return Ok(());
472→        }
473→
474→        // Check cancellation before copy
475→        if state.cancelled.load(Ordering::Relaxed) {
476→            return Err(WriteOperationError::Cancelled {
477→                message: "Operation cancelled by user".to_string(),
478→            });
479→        }
480→
481→        // Copy file using appropriate strategy (network, safe overwrite, or native)
482→        // Create progress callback for intra-file progress reporting on network filesystems
483→        let base_bytes_done = *bytes_done;
484→        let current_file_name = file_name.to_string_lossy().to_string();
485→        let last_emit_time = std::cell::Cell::new(Instant::now());
486→
487→        let progress_cb: ChunkedCopyProgressFn = &|chunk_bytes: u64, _total: u64| {
488→            if last_emit_time.get().elapsed() >= *progress_interval {
489→                let effective_bytes_done = base_bytes_done + chunk_bytes;
490→                log::debug!(
491→                    "copy: emitting chunked progress op={} files={}/{} bytes={}/{}",
492→                    operation_id,
493→                    *files_done,
494→                    files_total,
495→                    effective_bytes_done,
496→                    bytes_total
497→                );
498→                let _ = app.emit(
499→                    "write-progress",
500→                    WriteProgressEvent {
501→                        operation_id: operation_id.to_string(),
502→                        operation_type,
503→                        phase: WriteOperationPhase::Copying,
504→                        current_file: Some(current_file_name.clone()),
505→                        files_done: *files_done,
506→                        files_total,
507→                        bytes_done: effective_bytes_done,
508→                        bytes_total,
509→                    },
510→                );
511→                update_operation_status(
512→                    operation_id,
513→                    WriteOperationPhase::Copying,
514→                    Some(current_file_name.clone()),
515→                    *files_done,
516→                    files_total,
517→                    effective_bytes_done,
518→                    bytes_total,
519→                );
520→                last_emit_time.set(Instant::now());
521→            }
522→        };
523→
524→        let bytes = copy_file_with_strategy(
525→            source,
526→            &actual_dest,
527→            needs_safe_overwrite,
528→            &state.cancelled,
529→            Some(progress_cb),
530→        )?;
531→
532→        transaction.record_file(actual_dest.clone());
533→        *files_done += 1;
534→        *bytes_done += bytes;
535→
536→        // Emit progress
537→        if last_progress_time.elapsed() >= *progress_interval {
538→            let current_file_name = file_name.to_string_lossy().to_string();
539→            log::debug!(
540→                "copy: emitting write-progress op={} phase=copying files={}/{} bytes={}/{}",
541→                operation_id,
542→                *files_done,
543→                files_total,
544→                *bytes_done,
545→                bytes_total
546→            );
547→            let _ = app.emit(
548→                "write-progress",
549→                WriteProgressEvent {
550→                    operation_id: operation_id.to_string(),
551→                    operation_type,
552→                    phase: WriteOperationPhase::Copying,
553→                    current_file: Some(current_file_name.clone()),
554→                    files_done: *files_done,
555→                    files_total,
556→                    bytes_done: *bytes_done,
557→                    bytes_total,
558→                },
559→            );
560→            update_operation_status(
561→                operation_id,
562→                WriteOperationPhase::Copying,
563→                Some(current_file_name),
564→                *files_done,
565→                files_total,
566→                *bytes_done,
567→                bytes_total,
568→            );
569→            *last_progress_time = Instant::now();
570→        }
571→    }
572→
573→    Ok(())
574→}
