  1→//! Operation state management and caches.
  2→//!
  3→//! Contains state tracking for in-progress operations and status caches for query APIs.
  4→
  5→use std::collections::HashMap;
  6→use std::path::PathBuf;
  7→use std::sync::atomic::{AtomicBool, Ordering};
  8→use std::sync::{Arc, LazyLock, RwLock};
  9→use std::time::Duration;
 10→
 11→use super::types::{ConflictResolution, OperationStatus, OperationSummary, WriteOperationPhase, WriteOperationType};
 12→
 13→// ============================================================================
 14→// Operation state
 15→// ============================================================================
 16→
 17→/// State for an in-progress write operation.
 18→pub struct WriteOperationState {
 19→    /// Arc so it can be shared with native copy operations.
 20→    pub cancelled: Arc<AtomicBool>,
 21→    /// When true, keep partial files on cancellation.
 22→    pub skip_rollback: AtomicBool,
 23→    pub progress_interval: Duration,
 24→    /// Set by `resolve_write_conflict`.
 25→    pub pending_resolution: RwLock<Option<ConflictResolutionResponse>>,
 26→    pub conflict_condvar: std::sync::Condvar,
 27→    pub conflict_mutex: std::sync::Mutex<bool>,
 28→}
 29→
 30→/// Response to a conflict resolution request.
 31→#[derive(Debug, Clone)]
 32→pub struct ConflictResolutionResponse {
 33→    pub resolution: ConflictResolution,
 34→    pub apply_to_all: bool,
 35→}
 36→
 37→/// Global cache for in-progress write operation states.
 38→pub(super) static WRITE_OPERATION_STATE: LazyLock<RwLock<HashMap<String, Arc<WriteOperationState>>>> =
 39→    LazyLock::new(|| RwLock::new(HashMap::new()));
 40→
 41→/// Global cache for operation status (for query APIs).
 42→static OPERATION_STATUS_CACHE: LazyLock<RwLock<HashMap<String, OperationStatusInternal>>> =
 43→    LazyLock::new(|| RwLock::new(HashMap::new()));
 44→
 45→/// Internal status tracking for operations.
 46→#[derive(Debug, Clone)]
 47→struct OperationStatusInternal {
 48→    operation_type: WriteOperationType,
 49→    phase: WriteOperationPhase,
 50→    current_file: Option<String>,
 51→    files_done: usize,
 52→    files_total: usize,
 53→    bytes_done: u64,
 54→    bytes_total: u64,
 55→    started_at: u64,
 56→}
 57→
 58→// ============================================================================
 59→// Status cache management
 60→// ============================================================================
 61→
 62→/// Updates the internal status for an operation.
 63→pub(super) fn update_operation_status(
 64→    operation_id: &str,
 65→    phase: WriteOperationPhase,
 66→    current_file: Option<String>,
 67→    files_done: usize,
 68→    files_total: usize,
 69→    bytes_done: u64,
 70→    bytes_total: u64,
 71→) {
 72→    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write()
 73→        && let Some(status) = cache.get_mut(operation_id)
 74→    {
 75→        status.phase = phase;
 76→        status.current_file = current_file;
 77→        status.files_done = files_done;
 78→        status.files_total = files_total;
 79→        status.bytes_done = bytes_done;
 80→        status.bytes_total = bytes_total;
 81→    }
 82→}
 83→
 84→/// Registers a new operation in the status cache.
 85→pub(super) fn register_operation_status(operation_id: &str, operation_type: WriteOperationType) {
 86→    let now = std::time::SystemTime::now()
 87→        .duration_since(std::time::UNIX_EPOCH)
 88→        .map(|d| d.as_millis() as u64)
 89→        .unwrap_or(0);
 90→
 91→    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write() {
 92→        cache.insert(
 93→            operation_id.to_string(),
 94→            OperationStatusInternal {
 95→                operation_type,
 96→                phase: WriteOperationPhase::Scanning,
 97→                current_file: None,
 98→                files_done: 0,
 99→                files_total: 0,
100→                bytes_done: 0,
101→                bytes_total: 0,
102→                started_at: now,
103→            },
104→        );
105→    }
106→}
107→
108→/// Removes an operation from the status cache.
109→pub(super) fn unregister_operation_status(operation_id: &str) {
110→    if let Ok(mut cache) = OPERATION_STATUS_CACHE.write() {
111→        cache.remove(operation_id);
112→    }
113→}
114→
115→// ============================================================================
116→// Public query functions
117→// ============================================================================
118→
119→/// Lists all active write operations.
120→///
121→/// Returns a list of operation summaries for all currently running operations.
122→/// This is useful for showing a global progress view or managing multiple concurrent operations.
123→pub fn list_active_operations() -> Vec<OperationSummary> {
124→    let cache = match OPERATION_STATUS_CACHE.read() {
125→        Ok(c) => c,
126→        Err(_) => return Vec::new(),
127→    };
128→
129→    cache
130→        .iter()
131→        .map(|(id, status)| {
132→            let percent_complete = if status.bytes_total > 0 {
133→                ((status.bytes_done as f64 / status.bytes_total as f64) * 100.0).min(100.0) as u8
134→            } else if status.files_total > 0 {
135→                ((status.files_done as f64 / status.files_total as f64) * 100.0).min(100.0) as u8
136→            } else {
137→                0
138→            };
139→
140→            OperationSummary {
141→                operation_id: id.clone(),
142→                operation_type: status.operation_type,
143→                phase: status.phase,
144→                percent_complete,
145→                started_at: status.started_at,
146→            }
147→        })
148→        .collect()
149→}
150→
151→/// Gets the detailed status of a specific operation.
152→///
153→/// Returns `None` if the operation is not found (either never existed or already completed).
154→pub fn get_operation_status(operation_id: &str) -> Option<OperationStatus> {
155→    let cache = OPERATION_STATUS_CACHE.read().ok()?;
156→    let status = cache.get(operation_id)?;
157→
158→    // Check if the operation is still running
159→    let is_running = WRITE_OPERATION_STATE
160→        .read()
161→        .ok()
162→        .map(|c| c.contains_key(operation_id))
163→        .unwrap_or(false);
164→
165→    Some(OperationStatus {
166→        operation_id: operation_id.to_string(),
167→        operation_type: status.operation_type,
168→        phase: status.phase,
169→        is_running,
170→        current_file: status.current_file.clone(),
171→        files_done: status.files_done,
172→        files_total: status.files_total,
173→        bytes_done: status.bytes_done,
174→        bytes_total: status.bytes_total,
175→        started_at: status.started_at,
176→    })
177→}
