179→/// Cancels an in-progress write operation.
180→///
181→/// # Arguments
182→/// * `operation_id` - The operation ID to cancel
183→/// * `rollback` - If true, delete any partial files created. If false, keep them.
184→pub fn cancel_write_operation(operation_id: &str, rollback: bool) {
185→    if let Ok(cache) = WRITE_OPERATION_STATE.read()
186→        && let Some(state) = cache.get(operation_id)
187→    {
188→        state.cancelled.store(true, Ordering::Relaxed);
189→        state.skip_rollback.store(!rollback, Ordering::Relaxed);
190→        // Wake up any waiting conflict resolution
191→        let _guard = state.conflict_mutex.lock();
192→        state.conflict_condvar.notify_all();
193→    }
194→}
195→
196→/// Cancels all in-progress write operations with rollback.
197→///
198→/// Used as a safety net when the frontend is tearing down (beforeunload, hot-reload).
199→pub fn cancel_all_write_operations() {
200→    if let Ok(cache) = WRITE_OPERATION_STATE.read() {
201→        for (id, state) in cache.iter() {
202→            if !state.cancelled.load(Ordering::Relaxed) {
203→                log::info!("cancel_all_write_operations: cancelling op={id}");
204→                state.cancelled.store(true, Ordering::Relaxed);
205→                state.skip_rollback.store(false, Ordering::Relaxed);
206→                let _guard = state.conflict_mutex.lock();
207→                state.conflict_condvar.notify_all();
208→            }
209→        }
210→    }
211→}
212→
213→/// Resolves a pending conflict for an in-progress write operation.
214→///
215→/// When an operation encounters a conflict in Stop mode, it emits a WriteConflictEvent
216→/// and waits for this function to be called. The operation will then proceed with the
217→/// chosen resolution.
218→///
219→/// # Arguments
220→/// * `operation_id` - The operation ID that has a pending conflict
221→/// * `resolution` - How to resolve the conflict (Skip, Overwrite, or Rename)
222→/// * `apply_to_all` - If true, apply this resolution to all future conflicts in this operation
223→pub fn resolve_write_conflict(operation_id: &str, resolution: ConflictResolution, apply_to_all: bool) {
224→    if let Ok(cache) = WRITE_OPERATION_STATE.read()
225→        && let Some(state) = cache.get(operation_id)
226→    {
227→        // Set the pending resolution
228→        if let Ok(mut pending) = state.pending_resolution.write() {
229→            *pending = Some(ConflictResolutionResponse {
230→                resolution,
231→                apply_to_all,
232→            });
233→        }
234→        // Wake up the waiting operation
235→        let _guard = state.conflict_mutex.lock();
236→        state.conflict_condvar.notify_all();
237→    }
238→}
