271→/// File info collected during scan (used for sorting).
272→#[derive(Debug, Clone)]
273→pub(super) struct FileInfo {
274→    pub path: PathBuf,
275→    /// Parent of the original source (used to compute relative path for destination)
276→    pub source_root: PathBuf,
277→    pub size: u64,
278→    pub modified: u64, // Unix timestamp in seconds
279→    pub created: u64,  // Unix timestamp in seconds
280→    pub is_symlink: bool,
281→}
282→
283→impl FileInfo {
284→    pub fn new(path: PathBuf, source_root: PathBuf, metadata: &std::fs::Metadata) -> Self {
285→        use std::time::UNIX_EPOCH;
286→        Self {
287→            path,
288→            source_root,
289→            size: metadata.len(),
290→            modified: metadata
291→                .modified()
292→                .ok()
293→                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
294→                .map(|d| d.as_secs())
295→                .unwrap_or(0),
296→            created: metadata
297→                .created()
298→                .ok()
299→                .and_then(|t| t.duration_since(UNIX_EPOCH).ok())
300→                .map(|d| d.as_secs())
301→                .unwrap_or(0),
302→            is_symlink: metadata.is_symlink(),
303→        }
304→    }
305→
306→    /// Get extension for sorting (lowercase, empty string if none).
307→    pub fn extension(&self) -> String {
308→        self.path
309→            .extension()
310→            .map(|e| e.to_string_lossy().to_lowercase())
311→            .unwrap_or_default()
312→    }
313→
314→    /// Get filename for sorting (lowercase).
315→    pub fn name_lower(&self) -> String {
316→        self.path
317→            .file_name()
318→            .map(|n| n.to_string_lossy().to_lowercase())
319→            .unwrap_or_default()
320→    }
321→
322→    /// Compute the destination path for this file given the destination root.
323→    pub fn dest_path(&self, destination: &std::path::Path) -> PathBuf {
324→        // Strip source_root from path to get relative path, then join with destination
325→        if let Ok(relative) = self.path.strip_prefix(&self.source_root) {
326→            destination.join(relative)
327→        } else {
328→            // Fallback: just use the filename
329→            destination.join(self.path.file_name().unwrap_or_default())
330→        }
331→    }
332→}
