344→// ============================================================================
345→// Copy transaction for rollback
346→// ============================================================================
347→
348→/// Tracks created files/directories for rollback on failure.
349→///
350→/// If dropped without calling `commit()`, automatically rolls back
351→/// (deletes) all recorded files and directories. This ensures cleanup
352→/// even if a thread panics during the copy loop.
353→#[cfg_attr(test, derive(Debug))]
354→pub(crate) struct CopyTransaction {
355→    /// In creation order.
356→    pub created_files: Vec<PathBuf>,
357→    /// In creation order.
358→    pub created_dirs: Vec<PathBuf>,
359→    /// Set to `true` by `commit()` to prevent rollback on drop.
360→    committed: bool,
361→}
362→
363→impl CopyTransaction {
364→    pub fn new() -> Self {
365→        Self {
366→            created_files: Vec::new(),
367→            created_dirs: Vec::new(),
368→            committed: false,
369→        }
370→    }
371→
372→    pub fn record_file(&mut self, path: PathBuf) {
373→        self.created_files.push(path);
374→    }
375→
376→    pub fn record_dir(&mut self, path: PathBuf) {
377→        self.created_dirs.push(path);
378→    }
379→
380→    /// Rolls back all created files and directories.
381→    pub fn rollback(&self) {
382→        // Delete files first (in reverse order)
383→        for file in self.created_files.iter().rev() {
384→            let _ = std::fs::remove_file(file);
385→        }
386→        // Then directories (deepest first, already in reverse due to creation order)
387→        for dir in self.created_dirs.iter().rev() {
388→            let _ = std::fs::remove_dir(dir);
389→        }
390→    }
391→
392→    /// Marks the transaction as committed, preventing rollback on drop.
393→    pub fn commit(mut self) {
394→        self.committed = true;
395→    }
396→}
397→
398→impl Drop for CopyTransaction {
399→    fn drop(&mut self) {
400→        if !self.committed {
401→            log::warn!(
402→                "CopyTransaction dropped without commit, rolling back {} files and {} dirs",
403→                self.created_files.len(),
404→                self.created_dirs.len()
405→            );
406→            self.rollback();
407→        }
408→    }
409→}
