  1→//! Copy strategy selection for file operations.
  2→//!
  3→//! Encapsulates the decision of which copy method to use:
  4→//! - Network filesystems: chunked copy for responsive cancellation
  5→//! - Safe overwrite needed: temp file + rename pattern
  6→//! - macOS: native copyfile(3) with APFS clonefile support
  7→//! - Linux: copy_file_range(2) with reflink support on btrfs/XFS
  8→//! - Other platforms: std::fs::copy fallback
  9→
 10→#[cfg(not(any(target_os = "macos", target_os = "linux")))]
 11→use std::fs;
 12→use std::path::Path;
 13→use std::sync::Arc;
 14→use std::sync::atomic::AtomicBool;
 15→
 16→#[cfg(target_os = "linux")]
 17→use super::linux_copy::copy_single_file_linux;
 18→#[cfg(target_os = "macos")]
 19→use super::macos_copy::{CopyProgressContext, copy_single_file_native};
 20→
 21→use super::chunked_copy::{ChunkedCopyProgressFn, chunked_copy_with_metadata, is_network_filesystem};
 22→use super::helpers::safe_overwrite_file;
 23→#[cfg(not(any(target_os = "macos", target_os = "linux")))]
 24→use super::types::IoResultExt;
 25→use super::types::WriteOperationError;
 26→
 27→/// Copies file contents using the appropriate strategy based on destination type.
 28→///
 29→/// Strategy selection:
 30→/// - Network filesystems: chunked copy for responsive cancellation
 31→/// - Safe overwrite needed: temp file + rename pattern to preserve original on failure
 32→/// - macOS: native copyfile(3) with APFS clonefile support
 33→/// - Linux: copy_file_range(2) with reflink support on btrfs/XFS
 34→/// - Other platforms: std::fs::copy fallback
 35→#[cfg(target_os = "macos")]
 36→pub(super) fn copy_file_with_strategy(
 37→    source: &Path,
 38→    dest: &Path,
 39→    needs_safe_overwrite: bool,
 40→    cancelled: &Arc<AtomicBool>,
 41→    progress_callback: Option<ChunkedCopyProgressFn>,
 42→) -> Result<u64, WriteOperationError> {
 43→    if is_network_filesystem(dest) {
 44→        log::debug!(
 45→            "copy_file_with_strategy: using chunked copy for network destination {}",
 46→            dest.display()
 47→        );
 48→        chunked_copy_with_metadata(source, dest, cancelled, progress_callback)
 49→    } else if needs_safe_overwrite {
 50→        let context = CopyProgressContext::with_cancellation(Arc::clone(cancelled));
 51→        safe_overwrite_file(source, dest, Some(&context))
 52→    } else {
 53→        let context = CopyProgressContext::with_cancellation(Arc::clone(cancelled));
 54→        copy_single_file_native(source, dest, false, Some(&context))
 55→    }
 56→}
 57→
 58→#[cfg(target_os = "linux")]
 59→pub(super) fn copy_file_with_strategy(
 60→    source: &Path,
 61→    dest: &Path,
 62→    needs_safe_overwrite: bool,
 63→    cancelled: &Arc<AtomicBool>,
 64→    progress_callback: Option<ChunkedCopyProgressFn>,
 65→) -> Result<u64, WriteOperationError> {
 66→    if is_network_filesystem(dest) {
 67→        log::debug!(
 68→            "copy_file_with_strategy: using chunked copy for network destination {}",
 69→            dest.display()
 70→        );
 71→        chunked_copy_with_metadata(source, dest, cancelled, progress_callback)
 72→    } else if needs_safe_overwrite {
 73→        safe_overwrite_file(source, dest)
 74→    } else {
 75→        copy_single_file_linux(source, dest, false, cancelled, progress_callback)
 76→    }
 77→}
 78→
 79→#[cfg(not(any(target_os = "macos", target_os = "linux")))]
 80→pub(super) fn copy_file_with_strategy(
 81→    source: &Path,
 82→    dest: &Path,
 83→    needs_safe_overwrite: bool,
 84→    cancelled: &Arc<AtomicBool>,
 85→    progress_callback: Option<ChunkedCopyProgressFn>,
 86→) -> Result<u64, WriteOperationError> {
 87→    let _ = progress_callback; // Unused on this platform
 88→    if is_network_filesystem(dest) {
 89→        log::debug!(
 90→            "copy_file_with_strategy: using chunked copy for network destination {}",
 91→            dest.display()
 92→        );
 93→        chunked_copy_with_metadata(source, dest, cancelled, None)
 94→    } else if needs_safe_overwrite {
 95→        safe_overwrite_file(source, dest)
 96→    } else {
 97→        fs::copy(source, dest).with_path(source)
 98→    }
 99→}
