  1→//! Helper functions for write operations.
  2→//!
  3→//! Contains validation, conflict resolution, and utility functions.
  4→
  5→use std::collections::HashSet;
  6→use std::fs;
  7→use std::path::{Path, PathBuf};
  8→use std::sync::Arc;
  9→use std::sync::atomic::Ordering;
 10→use std::time::Duration;
 11→use uuid::Uuid;
 12→
 13→#[cfg(target_os = "macos")]
 14→use super::macos_copy::{CopyProgressContext, copy_single_file_native};
 15→
 16→use super::state::WriteOperationState;
 17→#[cfg(not(target_os = "macos"))]
 18→use super::types::IoResultExt;
 19→use super::types::{ConflictInfo, ConflictResolution, WriteConflictEvent, WriteOperationConfig, WriteOperationError};
 20→use crate::ignore_poison::IgnorePoison;
 21→
 22→// ============================================================================
 23→// Validation helpers
 24→// ============================================================================
 25→
 26→pub(crate) fn validate_sources(sources: &[PathBuf]) -> Result<(), WriteOperationError> {
 27→    for source in sources {
 28→        // Use symlink_metadata to check existence without following symlinks
 29→        if fs::symlink_metadata(source).is_err() {
 30→            return Err(WriteOperationError::SourceNotFound {
 31→                path: source.display().to_string(),
 32→            });
 33→        }
 34→    }
 35→    Ok(())
 36→}
 37→
 38→pub(crate) fn validate_destination(destination: &Path) -> Result<(), WriteOperationError> {
 39→    // Destination must exist and be a directory
 40→    if !destination.exists() {
 41→        return Err(WriteOperationError::SourceNotFound {
 42→            path: destination.display().to_string(),
 43→        });
 44→    }
 45→    if !destination.is_dir() {
 46→        return Err(WriteOperationError::IoError {
 47→            path: destination.display().to_string(),
 48→            message: "Destination must be a directory".to_string(),
 49→        });
 50→    }
 51→    Ok(())
 52→}
 53→
 54→pub(crate) fn validate_not_same_location(sources: &[PathBuf], destination: &Path) -> Result<(), WriteOperationError> {
 55→    for source in sources {
 56→        if let Some(parent) = source.parent()
 57→            && parent == destination
 58→        {
 59→            return Err(WriteOperationError::SameLocation {
 60→                path: source.display().to_string(),
 61→            });
 62→        }
 63→    }
 64→    Ok(())
 65→}
 66→
 67→pub(crate) fn validate_destination_not_inside_source(
 68→    sources: &[PathBuf],
 69→    destination: &Path,
 70→) -> Result<(), WriteOperationError> {
 71→    // Canonicalize destination to resolve symlinks and ".." segments that could
 72→    // bypass a naive starts_with check (like /foo/bar/../foo/sub → /foo/sub)
 73→    let canonical_dest = destination.canonicalize().unwrap_or_else(|_| destination.to_path_buf());
 74→
 75→    for source in sources {
 76→        if source.is_dir() {
 77→            let canonical_source = source.canonicalize().unwrap_or_else(|_| source.to_path_buf());
 78→            if canonical_dest.starts_with(&canonical_source) {
 79→                return Err(WriteOperationError::DestinationInsideSource {
 80→                    source: source.display().to_string(),
 81→                    destination: destination.display().to_string(),
 82→                });
 83→            }
 84→        }
 85→    }
 86→    Ok(())
 87→}
 88→
 89→/// Checks whether the destination directory is writable using access(W_OK).
 90→#[cfg(unix)]
 91→pub(crate) fn validate_destination_writable(destination: &Path) -> Result<(), WriteOperationError> {
 92→    use std::ffi::CString;
 93→    use std::os::unix::ffi::OsStrExt;
 94→
 95→    let c_path = CString::new(destination.as_os_str().as_bytes()).map_err(|_| WriteOperationError::IoError {
 96→        path: destination.display().to_string(),
 97→        message: "Invalid path".to_string(),
 98→    })?;
 99→
100→    // SAFETY: c_path is a valid null-terminated C string
101→    let result = unsafe { libc::access(c_path.as_ptr(), libc::W_OK) };
102→    if result != 0 {
103→        return Err(WriteOperationError::PermissionDenied {
104→            path: destination.display().to_string(),
105→            message: "Destination folder is not writable. Check folder permissions in Finder.".to_string(),
106→        });
107→    }
108→    Ok(())
109→}
110→
111→#[cfg(not(unix))]
112→pub(crate) fn validate_destination_writable(_destination: &Path) -> Result<(), WriteOperationError> {
113→    Ok(())
114→}
115→
116→/// Checks available disk space on the destination volume against required bytes.
117→/// Uses statvfs on Unix to query free space.
118→#[cfg(unix)]
119→pub(crate) fn validate_disk_space(destination: &Path, required_bytes: u64) -> Result<(), WriteOperationError> {
120→    use std::ffi::CString;
121→    use std::mem::MaybeUninit;
122→    use std::os::unix::ffi::OsStrExt;
123→
124→    let c_path = CString::new(destination.as_os_str().as_bytes()).map_err(|_| WriteOperationError::IoError {
125→        path: destination.display().to_string(),
126→        message: "Invalid path".to_string(),
127→    })?;
128→
129→    let mut stat = MaybeUninit::<libc::statvfs>::uninit();
130→    // SAFETY: c_path is a valid null-terminated C string, stat is a valid pointer
131→    let result = unsafe { libc::statvfs(c_path.as_ptr(), stat.as_mut_ptr()) };
132→    if result != 0 {
133→        // Cannot determine space — continue and let the OS report ENOSPC if it happens
134→        return Ok(());
135→    }
136→
137→    // SAFETY: statvfs succeeded, stat is initialized
138→    let stat = unsafe { stat.assume_init() };
139→    // These casts are needed on macOS where f_bavail/f_frsize may not be u64
140→    #[allow(
141→        clippy::unnecessary_cast,
142→        reason = "Required for macOS where statvfs fields are not u64"
143→    )]
144→    let available = stat.f_bavail as u64 * stat.f_frsize as u64;
145→
146→    if required_bytes > available {
147→        // Determine volume name from mount point for a friendlier message
148→        let volume_name = destination
149→            .ancestors()
150→            .find(|p| p.parent().is_some_and(|pp| pp == Path::new("/Volumes")))
151→            .and_then(|p| p.file_name())
152→            .map(|n| n.to_string_lossy().to_string());
153→
154→        return Err(WriteOperationError::InsufficientSpace {
155→            required: required_bytes,
156→            available,
157→            volume_name,
158→        });
159→    }
160→
161→    Ok(())
162→}
