169→/// Checks if source and destination resolve to the same file (same inode + device).
170→/// This prevents data loss when copying a file over itself via a symlink.
171→#[cfg(unix)]
172→pub(crate) fn is_same_file(source: &Path, destination: &Path) -> bool {
173→    use std::os::unix::fs::MetadataExt;
174→
175→    let src_meta = match fs::metadata(source) {
176→        Ok(m) => m,
177→        Err(_) => return false,
178→    };
179→    let dst_meta = match fs::metadata(destination) {
180→        Ok(m) => m,
181→        Err(_) => return false,
182→    };
183→
184→    src_meta.dev() == dst_meta.dev() && src_meta.ino() == dst_meta.ino()
185→}
