195→
196→/// Maximum file name length in bytes (APFS/HFS+ limit)
197→const MAX_NAME_BYTES: usize = 255;
198→/// Maximum path length in bytes (macOS PATH_MAX)
199→const MAX_PATH_BYTES: usize = 1024;
200→
201→/// Validates that a destination path doesn't exceed filesystem name/path length limits.
202→pub(crate) fn validate_path_length(dest_path: &Path) -> Result<(), WriteOperationError> {
203→    // Check total path length
204→    let path_str = dest_path.as_os_str();
205→    if path_str.len() > MAX_PATH_BYTES {
206→        return Err(WriteOperationError::IoError {
207→            path: dest_path.display().to_string(),
208→            message: format!("Path exceeds maximum length of {} bytes", MAX_PATH_BYTES),
209→        });
210→    }
211→
212→    // Check file name component length
213→    if let Some(name) = dest_path.file_name()
214→        && name.len() > MAX_NAME_BYTES
215→    {
216→        return Err(WriteOperationError::IoError {
217→            path: dest_path.display().to_string(),
218→            message: format!("File name exceeds maximum length of {} bytes", MAX_NAME_BYTES),
219→        });
220→    }
221→
222→    Ok(())
223→}
