280→/// Result of applying a conflict resolution.
281→#[derive(Debug)]
282→pub(super) struct ResolvedDestination {
283→    /// The path to write to
284→    pub path: PathBuf,
285→    /// Whether this is an overwrite that needs safe handling
286→    pub needs_safe_overwrite: bool,
287→}
288→
289→/// Resolves a file conflict based on the configured resolution mode.
290→/// Returns the resolved destination info, or None if the file should be skipped.
291→/// Also returns whether the resolution should be applied to all future conflicts.
292→#[allow(
293→    clippy::too_many_arguments,
294→    reason = "Recursive fn requires passing state through multiple levels"
295→)]
296→pub(super) fn resolve_conflict(
297→    source: &Path,
298→    dest_path: &Path,
299→    config: &WriteOperationConfig,
300→    app: &tauri::AppHandle,
301→    operation_id: &str,
302→    state: &Arc<WriteOperationState>,
303→    apply_to_all_resolution: &mut Option<ConflictResolution>,
304→) -> Result<Option<ResolvedDestination>, WriteOperationError> {
305→    use tauri::Emitter;
306→
307→    // Determine effective conflict resolution
308→    let resolution = if let Some(saved_resolution) = apply_to_all_resolution {
309→        // Use saved "apply to all" resolution
310→        *saved_resolution
311→    } else if config.overwrite {
312→        ConflictResolution::Overwrite
313→    } else {
314→        config.conflict_resolution
315→    };
316→
317→    match resolution {
318→        ConflictResolution::Stop => {
319→            // Emit conflict event for frontend to handle
320→            let source_meta = fs::metadata(source).ok();
321→            let dest_meta = fs::metadata(dest_path).ok();
322→
323→            let destination_is_newer = match (&source_meta, &dest_meta) {
324→                (Some(s), Some(d)) => {
325→                    let src_time = s.modified().ok();
326→                    let dst_time = d.modified().ok();
327→                    matches!((src_time, dst_time), (Some(src), Some(dst)) if dst > src)
328→                }
329→                _ => false,
330→            };
331→
332→            let source_size = source_meta.as_ref().map(|m| m.len()).unwrap_or(0);
333→            let destination_size = dest_meta.as_ref().map(|m| m.len()).unwrap_or(0);
334→            let size_difference = destination_size as i64 - source_size as i64;
335→
336→            let source_modified = source_meta
337→                .as_ref()
338→                .and_then(|m| m.modified().ok())
339→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
340→                .map(|d| d.as_secs() as i64);
341→
342→            let destination_modified = dest_meta
343→                .as_ref()
344→                .and_then(|m| m.modified().ok())
345→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
346→                .map(|d| d.as_secs() as i64);
347→
348→            let _ = app.emit(
349→                "write-conflict",
350→                WriteConflictEvent {
351→                    operation_id: operation_id.to_string(),
352→                    source_path: source.display().to_string(),
353→                    destination_path: dest_path.display().to_string(),
354→                    source_size,
355→                    destination_size,
356→                    source_modified,
357→                    destination_modified,
358→                    destination_is_newer,
359→                    size_difference,
360→                },
361→            );
362→
363→            // Wait for user to call resolve_write_conflict.
364→            // The frontend cancels the operation if the dialog is destroyed, so this timeout
365→            // is only a safety net for when the frontend is completely dead (crash/hang).
366→            let guard = state.conflict_mutex.lock_ignore_poison();
367→            let (_guard, wait_result) = state
368→                .conflict_condvar
369→                .wait_timeout_while(guard, Duration::from_secs(30), |_| {
370→                    // Keep waiting while:
371→                    // 1. No pending resolution
372→                    // 2. Not cancelled
373→                    let has_resolution = state.pending_resolution.read().map(|r| r.is_some()).unwrap_or(false);
374→                    let is_cancelled = state.cancelled.load(Ordering::Relaxed);
375→                    !has_resolution && !is_cancelled
376→                })
377→                .unwrap();
378→
379→            // Safety net: if we timed out without a resolution, cancel
380→            if wait_result.timed_out() {
381→                return Err(WriteOperationError::Cancelled {
382→                    message: "Conflict resolution timed out — frontend may have disconnected".to_string(),
383→                });
384→            }
385→
386→            // Check if cancelled
387→            if state.cancelled.load(Ordering::Relaxed) {
388→                return Err(WriteOperationError::Cancelled {
389→                    message: "Operation cancelled by user".to_string(),
390→                });
391→            }
392→
393→            // Get the resolution
394→            let response = state.pending_resolution.write().ok().and_then(|mut r| r.take());
395→
396→            if let Some(response) = response {
397→                // Save for future conflicts if apply_to_all
398→                if response.apply_to_all {
399→                    *apply_to_all_resolution = Some(response.resolution);
400→                }
401→
402→                // Now apply the chosen resolution
403→                apply_resolution(response.resolution, dest_path)
404→            } else {
405→                // No resolution provided, treat as error
406→                Err(WriteOperationError::DestinationExists {
407→                    path: dest_path.display().to_string(),
408→                })
409→            }
410→        }
411→        ConflictResolution::Skip => Ok(None),
412→        ConflictResolution::Overwrite => apply_resolution(ConflictResolution::Overwrite, dest_path),
413→        ConflictResolution::Rename => apply_resolution(ConflictResolution::Rename, dest_path),
414→    }
415→}
416→
417→/// Applies a specific conflict resolution to a destination path.
418→/// Returns None for Skip, or ResolvedDestination with path and overwrite flag.
419→fn apply_resolution(
420→    resolution: ConflictResolution,
421→    dest_path: &Path,
422→) -> Result<Option<ResolvedDestination>, WriteOperationError> {
423→    match resolution {
424→        ConflictResolution::Stop => {
425→            // Should not happen - Stop waits for user input
426→            Err(WriteOperationError::DestinationExists {
427→                path: dest_path.display().to_string(),
428→            })
429→        }
430→        ConflictResolution::Skip => Ok(None),
431→        ConflictResolution::Overwrite => {
432→            // Don't delete here - the copy function will use safe overwrite pattern
433→            Ok(Some(ResolvedDestination {
434→                path: dest_path.to_path_buf(),
435→                needs_safe_overwrite: true,
436→            }))
437→        }
438→        ConflictResolution::Rename => {
439→            // Find a unique name by appending " (1)", " (2)", etc.
440→            let unique_path = find_unique_name(dest_path);
441→            Ok(Some(ResolvedDestination {
442→                path: unique_path,
443→                needs_safe_overwrite: false,
444→            }))
445→        }
446→    }
447→}
448→
449→/// Finds a unique filename by appending " (1)", " (2)", etc.
450→pub(super) fn find_unique_name(path: &Path) -> PathBuf {
451→    let parent = path.parent().unwrap_or(Path::new(""));
452→    let stem = path
453→        .file_stem()
454→        .map(|s| s.to_string_lossy().to_string())
455→        .unwrap_or_default();
456→    let extension = path.extension().map(|s| s.to_string_lossy().to_string());
457→
458→    let mut counter = 1;
459→    loop {
460→        let new_name = match &extension {
461→            Some(ext) => format!("{} ({}).{}", stem, counter, ext),
462→            None => format!("{} ({})", stem, counter),
463→        };
464→        let new_path = parent.join(new_name);
465→        if !new_path.exists() {
466→            return new_path;
467→        }
468→        counter += 1;
469→    }
470→}
