472→// ============================================================================
473→// Safe overwrite helpers
474→// ============================================================================
475→
476→/// Performs a safe overwrite using temp+rename pattern.
477→/// This ensures the original file is preserved if the copy fails.
478→///
479→/// Steps:
480→/// 1. Copy source to `dest.cmdr-tmp-{uuid}` (temp file in same directory)
481→/// 2. Rename original dest to `dest.cmdr-backup-{uuid}`
482→/// 3. Rename temp to final dest path
483→/// 4. Delete backup
484→///
485→/// If any step fails before step 3 completes, the original dest is intact.
486→pub(super) fn safe_overwrite_file(
487→    source: &Path,
488→    dest: &Path,
489→    #[cfg(target_os = "macos")] context: Option<&CopyProgressContext>,
490→) -> Result<u64, WriteOperationError> {
491→    let uuid = Uuid::new_v4();
492→    let parent = dest.parent().unwrap_or(Path::new("."));
493→    let file_name = dest
494→        .file_name()
495→        .map(|n| n.to_string_lossy().to_string())
496→        .unwrap_or_default();
497→
498→    let temp_path = parent.join(format!("{}.cmdr-tmp-{}", file_name, uuid));
499→    let backup_path = parent.join(format!("{}.cmdr-backup-{}", file_name, uuid));
500→
501→    // Step 1: Copy source to temp
502→    #[cfg(target_os = "macos")]
503→    let bytes = copy_single_file_native(source, &temp_path, false, context)?;
504→    #[cfg(not(target_os = "macos"))]
505→    let bytes = fs::copy(source, &temp_path).with_path(source)?;
506→
507→    // Step 2: Rename original dest to backup
508→    if let Err(e) = fs::rename(dest, &backup_path) {
509→        // Failed to backup - clean up temp and return error
510→        let _ = fs::remove_file(&temp_path);
511→        return Err(WriteOperationError::IoError {
512→            path: dest.display().to_string(),
513→            message: format!("Failed to backup existing file: {}", e),
514→        });
515→    }
516→
517→    // Step 3: Rename temp to final dest
518→    if let Err(e) = fs::rename(&temp_path, dest) {
519→        // Failed to rename - restore backup and clean up
520→        let _ = fs::rename(&backup_path, dest);
521→        let _ = fs::remove_file(&temp_path);
522→        return Err(WriteOperationError::IoError {
523→            path: dest.display().to_string(),
524→            message: format!("Failed to finalize overwrite: {}", e),
525→        });
526→    }
527→
528→    // Step 4: Delete backup (non-critical, ignore errors)
529→    let _ = fs::remove_file(&backup_path);
530→
531→    Ok(bytes)
532→}
533→
534→/// Performs a safe overwrite for directories using temp+rename pattern.
535→pub(super) fn safe_overwrite_dir(dest: &Path) -> Result<PathBuf, WriteOperationError> {
536→    let uuid = Uuid::new_v4();
537→    let parent = dest.parent().unwrap_or(Path::new("."));
538→    let file_name = dest
539→        .file_name()
540→        .map(|n| n.to_string_lossy().to_string())
541→        .unwrap_or_default();
542→
543→    let backup_path = parent.join(format!("{}.cmdr-backup-{}", file_name, uuid));
544→
545→    // Rename original dest to backup
546→    fs::rename(dest, &backup_path).map_err(|e| WriteOperationError::IoError {
547→        path: dest.display().to_string(),
548→        message: format!("Failed to backup existing directory: {}", e),
549→    })?;
550→
551→    // Return the backup path so caller can delete it after successful copy
552→    Ok(backup_path)
553→}
