559→/// Calculates destination path for a source file relative to source root.
560→pub(super) fn calculate_dest_path(
561→    path: &Path,
562→    source_root: &Path,
563→    dest_root: &Path,
564→) -> Result<PathBuf, WriteOperationError> {
565→    // If path is the source root itself, use the file name in dest_root
566→    if path == source_root {
567→        let file_name = path.file_name().ok_or_else(|| WriteOperationError::IoError {
568→            path: path.display().to_string(),
569→            message: "Invalid source path".to_string(),
570→        })?;
571→        return Ok(dest_root.join(file_name));
572→    }
573→
574→    // Otherwise, strip the source root's parent and join with dest_root
575→    let source_parent = source_root.parent().unwrap_or(source_root);
576→    let relative = path
577→        .strip_prefix(source_parent)
578→        .map_err(|_| WriteOperationError::IoError {
579→            path: path.display().to_string(),
580→            message: "Failed to calculate relative path".to_string(),
581→        })?;
582→
583→    Ok(dest_root.join(relative))
584→}
