586→/// Creates ConflictInfo for a source/destination pair.
587→pub(super) fn create_conflict_info(
588→    source: &Path,
589→    dest: &Path,
590→    source_metadata: &fs::Metadata,
591→) -> Result<Option<ConflictInfo>, WriteOperationError> {
592→    let dest_metadata = match fs::symlink_metadata(dest) {
593→        Ok(m) => m,
594→        Err(_) => return Ok(None), // No conflict if dest doesn't exist
595→    };
596→
597→    let source_modified = source_metadata
598→        .modified()
599→        .ok()
600→        .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
601→        .map(|d| d.as_secs());
602→
603→    let dest_modified = dest_metadata
604→        .modified()
605→        .ok()
606→        .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
607→        .map(|d| d.as_secs());
608→
609→    let destination_is_newer = match (source_modified, dest_modified) {
610→        (Some(s), Some(d)) => d > s,
611→        _ => false,
612→    };
613→
614→    Ok(Some(ConflictInfo {
615→        source_path: source.display().to_string(),
616→        destination_path: dest.display().to_string(),
617→        source_size: source_metadata.len(),
618→        destination_size: dest_metadata.len(),
619→        source_modified,
620→        destination_modified: dest_modified,
621→        destination_is_newer,
622→        is_directory: source_metadata.is_dir(),
623→    }))
624→}
