626→/// Samples conflicts if there are too many, using reservoir sampling.
627→pub(super) fn sample_conflicts(conflicts: Vec<ConflictInfo>, max_count: usize) -> (Vec<ConflictInfo>, bool) {
628→    if conflicts.len() <= max_count {
629→        return (conflicts, false);
630→    }
631→
632→    // Use reservoir sampling for uniform random selection
633→    use std::collections::hash_map::DefaultHasher;
634→    use std::hash::{Hash, Hasher};
635→
636→    let mut sampled: Vec<ConflictInfo> = conflicts.iter().take(max_count).cloned().collect();
637→
638→    for (i, conflict) in conflicts.iter().enumerate().skip(max_count) {
639→        // Deterministic "random" based on path hash for reproducibility
640→        let mut hasher = DefaultHasher::new();
641→        conflict.source_path.hash(&mut hasher);
642→        i.hash(&mut hasher);
643→        let hash = hasher.finish();
644→        let j = (hash as usize) % (i + 1);
645→
646→        if j < max_count {
647→            sampled[j] = conflict.clone();
648→        }
649→    }
650→
651→    (sampled, true)
652→}
