654→// ============================================================================
655→// Cancellation-aware execution
656→// ============================================================================
657→
658→/// Interval for checking cancellation while waiting for blocking operations.
659→const CANCELLATION_POLL_INTERVAL: Duration = Duration::from_millis(100);
660→
661→/// Runs a closure on a background thread with polling-based cancellation.
662→///
663→/// Spawns `work` on a new thread and polls for results every 100ms, checking the
664→/// cancellation flag between polls. This ensures quick cancellation response even
665→/// when filesystem I/O blocks (for example, on stuck network drives).
666→pub(super) fn run_cancellable<T>(
667→    work: impl FnOnce() -> Result<T, WriteOperationError> + Send + 'static,
668→    state: &Arc<WriteOperationState>,
669→    context: &str,
670→    operation_id: &str,
671→) -> Result<T, WriteOperationError>
672→where
673→    T: Send + 'static,
674→{
675→    use std::sync::mpsc;
676→
677→    let (tx, rx) = mpsc::channel();
678→
679→    std::thread::spawn(move || {
680→        let _ = tx.send(work());
681→    });
682→
683→    loop {
684→        if state.cancelled.load(Ordering::Relaxed) {
685→            log::debug!("{context}: cancellation detected during polling op={operation_id}");
686→            return Err(WriteOperationError::Cancelled {
687→                message: "Operation cancelled by user".to_string(),
688→            });
689→        }
690→
691→        match rx.recv_timeout(CANCELLATION_POLL_INTERVAL) {
692→            Ok(result) => return result,
693→            Err(mpsc::RecvTimeoutError::Timeout) => {}
694→            Err(mpsc::RecvTimeoutError::Disconnected) => {
695→                return Err(WriteOperationError::IoError {
696→                    path: context.to_string(),
697→                    message: format!("{context} thread terminated unexpectedly"),
698→                });
699→            }
700→        }
701→    }
702→}
