101→/// Core mkdir logic, separated from the Tauri command so it can be tested without `AppHandle`.
102→async fn create_directory_core(
103→    volume_id: Option<String>,
104→    parent_path: &str,
105→    name: &str,
106→) -> Result<(PathBuf, String), IpcError> {
107→    if name.is_empty() {
108→        return Err(IpcError::from_err("Folder name cannot be empty"));
109→    }
110→    if name.contains('/') || name.contains('\0') {
111→        return Err(IpcError::from_err("Folder name contains invalid characters"));
112→    }
113→
114→    let volume_id = volume_id.unwrap_or_else(|| "root".to_string());
115→
116→    // For local volumes, expand tilde
117→    let expanded_path = if volume_id == "root" {
118→        expand_tilde(parent_path)
119→    } else {
120→        parent_path.to_string()
121→    };
122→
123→    // Try to use Volume abstraction
124→    if let Some(volume) = get_volume_manager().get(&volume_id) {
125→        let new_path = PathBuf::from(&expanded_path).join(name);
126→        let new_path_clone = new_path.clone();
127→        let parent_path_owned = parent_path.to_string();
128→        let name_owned = name.to_string();
129→
130→        // Use spawn_blocking to run the Volume operation in a context where
131→        // tokio::runtime::Handle::current() is available (needed for MtpVolume)
132→        tokio::time::timeout(
133→            Duration::from_secs(5),
134→            tokio::task::spawn_blocking(move || {
135→                volume.create_directory(&new_path_clone).map_err(|e| match e {
136→                    crate::file_system::VolumeError::AlreadyExists(_) => {
137→                        format!("'{}' already exists", name_owned)
138→                    }
139→                    crate::file_system::VolumeError::PermissionDenied(_) => {
140→                        format!(
141→                            "Permission denied: cannot create '{}' in '{}'",
142→                            name_owned, parent_path_owned
143→                        )
144→                    }
145→                    _ => format!("Couldn't create folder: {}", e),
146→                })
147→            }),
148→        )
149→        .await
150→        .map_err(|_| IpcError::timeout())?
151→        .map_err(|e| IpcError::from_err(format!("Task failed: {}", e)))?
152→        .map_err(IpcError::from_err)?;
153→
154→        return Ok((new_path, expanded_path));
155→    }
156→
157→    // Fallback for unknown volumes (shouldn't happen in practice)
158→    let mut new_path = PathBuf::from(&expanded_path);
159→    new_path.push(name);
160→    std::fs::create_dir(&new_path)
161→        .map_err(|e| match e.kind() {
162→            std::io::ErrorKind::AlreadyExists => format!("'{}' already exists", name),
163→            std::io::ErrorKind::PermissionDenied => {
164→                format!("Permission denied: cannot create '{}' in '{}'", name, parent_path)
165→            }
166→            _ => format!("Couldn't create folder: {}", e),
167→        })
168→        .map_err(IpcError::from_err)?;
169→
170→    Ok((new_path, expanded_path))
171→}
