  1→//! Linux-native file copy using `copy_file_range(2)`.
  2→//!
  3→//! Performs kernel-side copies with progress tracking and cancellation.
  4→//! On btrfs/XFS this produces reflink copies (instant, COW) similar to
  5→//! APFS clonefile on macOS. On other filesystems it falls back to an
  6→//! in-kernel data copy, still faster than userspace read/write.
  7→
  8→use std::fs;
  9→use std::os::unix::io::AsRawFd;
 10→use std::path::Path;
 11→use std::sync::Arc;
 12→use std::sync::atomic::{AtomicBool, Ordering};
 13→
 14→use super::types::WriteOperationError;
 15→
 16→/// Chunk size per `copy_file_range` call (4 MB).
 17→/// Larger than chunked_copy's 1 MB because this is an in-kernel operation
 18→/// with no userspace buffer overhead. Cancellation is still checked between
 19→/// iterations.
 20→const COPY_RANGE_CHUNK: usize = 4 * 1024 * 1024;
 21→
 22→/// Copies a single file using `copy_file_range(2)` with progress tracking.
 23→///
 24→/// Returns the number of bytes copied on success.
 25→///
 26→/// # Arguments
 27→/// * `source` - Source file path
 28→/// * `destination` - Destination file path (will be created/overwritten)
 29→/// * `overwrite` - If true, overwrite existing destination
 30→/// * `cancelled` - Cancellation flag checked between chunks
 31→/// * `progress_callback` - Optional callback called with (bytes_so_far, total)
 32→pub fn copy_single_file_linux(
 33→    source: &Path,
 34→    destination: &Path,
 35→    overwrite: bool,
 36→    cancelled: &Arc<AtomicBool>,
 37→    progress_callback: Option<&dyn Fn(u64, u64)>,
 38→) -> Result<u64, WriteOperationError> {
 39→    let src_file = fs::File::open(source).map_err(|e| map_io_error(e, source, destination))?;
 40→
 41→    let src_metadata = src_file.metadata().map_err(|e| WriteOperationError::IoError {
 42→        path: source.display().to_string(),
 43→        message: format!("Failed to read source metadata: {}", e),
 44→    })?;
 45→    let total_size = src_metadata.len();
 46→
 47→    // Open destination, respecting overwrite flag
 48→    let dst_file = if overwrite {
 49→        fs::File::create(destination)
 50→    } else {
 51→        fs::OpenOptions::new().write(true).create_new(true).open(destination)
 52→    }
 53→    .map_err(|e| map_io_error(e, source, destination))?;
 54→
 55→    // Pre-allocate space to avoid fragmentation
 56→    if total_size > 0 {
 57→        let _ = unsafe { libc::posix_fallocate(dst_file.as_raw_fd(), 0, total_size as libc::off_t) };
 58→    }
 59→
 60→    let src_fd = src_file.as_raw_fd();
 61→    let dst_fd = dst_file.as_raw_fd();
 62→    let mut bytes_copied: u64 = 0;
 63→    let mut src_offset: libc::off64_t = 0;
 64→    let mut dst_offset: libc::off64_t = 0;
 65→
 66→    while bytes_copied < total_size {
 67→        // Check cancellation before each chunk
 68→        if cancelled.load(Ordering::Relaxed) {
 69→            log::info!("linux_copy: cancelled after {} bytes, cleaning up", bytes_copied);
 70→            drop(dst_file);
 71→            let _ = fs::remove_file(destination);
 72→            return Err(WriteOperationError::Cancelled {
 73→                message: "Operation cancelled by user".to_string(),
 74→            });
 75→        }
 76→
 77→        let remaining = total_size - bytes_copied;
 78→        let chunk = remaining.min(COPY_RANGE_CHUNK as u64) as usize;
 79→
 80→        // SAFETY: File descriptors are valid (owned by src_file/dst_file).
 81→        // Offsets are valid pointers to stack variables.
 82→        let result = unsafe {
 83→            libc::copy_file_range(
 84→                src_fd,
 85→                &mut src_offset,
 86→                dst_fd,
 87→                &mut dst_offset,
 88→                chunk,
 89→                0, // flags (must be 0)
 90→            )
 91→        };
 92→
 93→        if result < 0 {
 94→            let err = std::io::Error::last_os_error();
 95→            drop(dst_file);
 96→            let _ = fs::remove_file(destination);
 97→            return Err(map_io_error(err, source, destination));
 98→        }
 99→
100→        if result == 0 {
101→            // Unexpected EOF - source file may have been truncated
102→            break;
103→        }
104→
105→        bytes_copied += result as u64;
106→
107→        if let Some(cb) = progress_callback {
108→            cb(bytes_copied, total_size);
109→        }
110→    }
111→
112→    // Copy permissions from source
113→    let permissions = src_metadata.permissions();
114→    if let Err(e) = fs::set_permissions(destination, permissions) {
115→        log::warn!(
116→            "linux_copy: failed to set permissions on {}: {}",
117→            destination.display(),
118→            e
119→        );
120→    }
121→
122→    log::info!(
123→        "linux_copy: copied {} bytes from {} to {}",
124→        bytes_copied,
125→        source.display(),
126→        destination.display()
127→    );
128→
129→    Ok(bytes_copied)
130→}
