269→/// Copies ACLs (access control lists) from source to destination.
270→#[cfg(any(target_os = "macos", target_os = "linux", target_os = "freebsd"))]
271→fn copy_acls(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
272→    use exacl::{AclOption, getfacl, setfacl};
273→
274→    // Get ACL from source (best effort - not all filesystems support ACLs)
275→    let acl = match getfacl(source, AclOption::empty()) {
276→        Ok(acl) => acl,
277→        Err(e) => {
278→            log::debug!("copy_acls: failed to get ACL from {}: {}", source.display(), e);
279→            return Ok(());
280→        }
281→    };
282→
283→    // Set ACL on destination
284→    if let Err(e) = setfacl(&[dest], &acl, AclOption::empty()) {
285→        log::debug!("copy_acls: failed to set ACL on {}: {}", dest.display(), e);
286→    }
287→
288→    Ok(())
289→}
