297→/// Copies timestamps (mtime, atime) from source to destination.
298→fn copy_timestamps(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
299→    let metadata = std::fs::metadata(source).map_err(|e| WriteOperationError::IoError {
300→        path: source.display().to_string(),
301→        message: format!("Failed to read source metadata: {}", e),
302→    })?;
303→
304→    let mtime = filetime::FileTime::from_last_modification_time(&metadata);
305→    let atime = filetime::FileTime::from_last_access_time(&metadata);
306→
307→    filetime::set_file_times(dest, atime, mtime).map_err(|e| WriteOperationError::IoError {
308→        path: dest.display().to_string(),
309→        message: format!("Failed to set timestamps: {}", e),
310→    })?;
311→
312→    Ok(())
313→}
314→
315→/// Copies permissions from source to destination.
316→fn copy_permissions(source: &Path, dest: &Path) -> Result<(), WriteOperationError> {
317→    let metadata = std::fs::metadata(source).map_err(|e| WriteOperationError::IoError {
318→        path: source.display().to_string(),
319→        message: format!("Failed to read source metadata: {}", e),
320→    })?;
321→
322→    std::fs::set_permissions(dest, metadata.permissions()).map_err(|e| WriteOperationError::IoError {
323→        path: dest.display().to_string(),
324→        message: format!("Failed to set permissions: {}", e),
325→    })?;
326→
327→    Ok(())
328→}
