 90→/// Spawns a write operation in the background with state management and panic handling.
 91→///
 92→/// Creates `WriteOperationState`, registers the operation, spawns `tokio::spawn` +
 93→/// `spawn_blocking`, and handles cleanup and panic recovery. Callers do validation
 94→/// and logging before calling this, then pass a closure for the actual work.
 95→async fn start_write_operation<F>(
 96→    app: tauri::AppHandle,
 97→    operation_type: WriteOperationType,
 98→    progress_interval_ms: u64,
 99→    handler: F,
100→) -> Result<WriteOperationStartResult, WriteOperationError>
101→where
102→    F: FnOnce(tauri::AppHandle, String, Arc<WriteOperationState>) -> Result<(), WriteOperationError> + Send + 'static,
103→{
104→    let operation_id = Uuid::new_v4().to_string();
105→    let state = Arc::new(WriteOperationState {
106→        cancelled: Arc::new(AtomicBool::new(false)),
107→        skip_rollback: AtomicBool::new(false),
108→        progress_interval: Duration::from_millis(progress_interval_ms),
109→        pending_resolution: std::sync::RwLock::new(None),
110→        conflict_condvar: std::sync::Condvar::new(),
111→        conflict_mutex: std::sync::Mutex::new(false),
112→    });
113→
114→    if let Ok(mut cache) = WRITE_OPERATION_STATE.write() {
115→        cache.insert(operation_id.clone(), Arc::clone(&state));
116→    }
117→    register_operation_status(&operation_id, operation_type);
118→
119→    let operation_id_for_spawn = operation_id.clone();
120→
121→    tokio::spawn(async move {
122→        let operation_id_for_cleanup = operation_id_for_spawn.clone();
123→        let app_for_error = app.clone();
124→
125→        let result = tokio::task::spawn_blocking(move || handler(app, operation_id_for_spawn, state)).await;
126→
127→        if let Ok(mut cache) = WRITE_OPERATION_STATE.write() {
128→            cache.remove(&operation_id_for_cleanup);
129→        }
130→        unregister_operation_status(&operation_id_for_cleanup);
131→
132→        if let Err(e) = result {
133→            use tauri::Emitter;
134→            let _ = app_for_error.emit(
135→                "write-error",
136→                WriteErrorEvent {
137→                    operation_id: operation_id_for_cleanup,
138→                    operation_type,
139→                    error: WriteOperationError::IoError {
140→                        path: String::new(),
141→                        message: format!("Task failed: {}", e),
142→                    },
143→                },
144→            );
145→        }
146→    });
147→
148→    Ok(WriteOperationStartResult {
149→        operation_id,
150→        operation_type,
151→    })
152→}
