 29→
 30→type CopyfileStateT = *mut c_void;
 31→type CopyfileFlagsT = u32;
 32→
 33→// copyfile flags from /usr/include/copyfile.h
 34→const COPYFILE_ACL: CopyfileFlagsT = 1 << 0;
 35→const COPYFILE_STAT: CopyfileFlagsT = 1 << 1;
 36→const COPYFILE_XATTR: CopyfileFlagsT = 1 << 2;
 37→const COPYFILE_DATA: CopyfileFlagsT = 1 << 3;
 38→const COPYFILE_ALL: CopyfileFlagsT = COPYFILE_ACL | COPYFILE_STAT | COPYFILE_XATTR | COPYFILE_DATA;
 39→const COPYFILE_RECURSIVE: CopyfileFlagsT = 1 << 15;
 40→const COPYFILE_EXCL: CopyfileFlagsT = 1 << 17;
 41→const COPYFILE_NOFOLLOW_SRC: CopyfileFlagsT = 1 << 18;
 42→const COPYFILE_CLONE: CopyfileFlagsT = 1 << 24;
 43→
 44→// copyfile_state constants
 45→const COPYFILE_STATE_STATUS_CB: c_int = 6;
 46→const COPYFILE_STATE_SRC_FILENAME: c_int = 1;
 47→const COPYFILE_STATE_DST_FILENAME: c_int = 2;
 48→const COPYFILE_STATE_COPIED: c_int = 8;
 49→const COPYFILE_STATE_STATUS_CTX: c_int = 7;
 50→
 51→// Progress callback return values
 52→const COPYFILE_CONTINUE: c_int = 0;
 53→const COPYFILE_QUIT: c_int = 1;
 54→
 55→// Progress callback what values
 56→const COPYFILE_RECURSE_FILE: c_int = 1;
 57→const COPYFILE_COPY_DATA: c_int = 4;
 58→
 59→// Progress callback stage values
 60→const COPYFILE_START: c_int = 1;
 61→const COPYFILE_FINISH: c_int = 2;
 62→const COPYFILE_PROGRESS: c_int = 4;
 63→
 64→#[link(name = "System", kind = "dylib")]
 65→unsafe extern "C" {
 66→    fn copyfile(from: *const i8, to: *const i8, state: CopyfileStateT, flags: CopyfileFlagsT) -> c_int;
 67→
 68→    fn copyfile_state_alloc() -> CopyfileStateT;
 69→    fn copyfile_state_free(state: CopyfileStateT) -> c_int;
 70→    fn copyfile_state_set(state: CopyfileStateT, flag: c_int, value: *const c_void) -> c_int;
 71→    fn copyfile_state_get(state: CopyfileStateT, flag: c_int, value: *mut c_void) -> c_int;
 72→}
