240→/// Copies a file or directory using macOS copyfile(3).
241→///
242→/// This preserves:
243→/// - Extended attributes (xattrs)
244→/// - ACLs
245→/// - Resource forks
246→/// - Finder metadata
247→/// - Uses clonefile on APFS for instant copies
248→///
249→/// # Arguments
250→/// * `source` - Source file or directory path
251→/// * `destination` - Destination path (will be created)
252→/// * `options` - Copy options
253→/// * `context` - Progress context for cancellation and callbacks (optional)
254→///
255→/// # Returns
256→/// * `Ok(())` on success
257→/// * `Err(WriteOperationError)` on failure
258→pub fn copy_file_native(
259→    source: &Path,
260→    destination: &Path,
261→    options: CopyOptions,
262→    context: Option<&CopyProgressContext>,
263→) -> Result<(), WriteOperationError> {
264→    let src_cstring = path_to_cstring(source)?;
265→    let dst_cstring = path_to_cstring(destination)?;
266→
267→    // Build flags
268→    let mut flags: CopyfileFlagsT = COPYFILE_ALL | COPYFILE_CLONE;
269→
270→    if options.preserve_symlinks {
271→        flags |= COPYFILE_NOFOLLOW_SRC;
272→    }
273→
274→    if options.exclusive {
275→        flags |= COPYFILE_EXCL;
276→    }
277→
278→    if options.recursive && source.is_dir() {
279→        flags |= COPYFILE_RECURSIVE;
280→    }
281→
282→    // If not exclusive and destination exists, remove it first
283→    // (copyfile doesn't have a built-in overwrite mode)
284→    if !options.exclusive && destination.exists() {
285→        if destination.is_dir() {
286→            std::fs::remove_dir_all(destination).map_err(|e| WriteOperationError::IoError {
287→                path: destination.display().to_string(),
288→                message: format!("Failed to remove existing destination: {}", e),
289→            })?;
290→        } else {
291→            std::fs::remove_file(destination).map_err(|e| WriteOperationError::IoError {
292→                path: destination.display().to_string(),
293→                message: format!("Failed to remove existing destination: {}", e),
294→            })?;
295→        }
296→    }
297→
298→    // Set up state for progress callbacks if context provided
299→    let state = unsafe { copyfile_state_alloc() };
300→    if state.is_null() {
301→        return Err(WriteOperationError::IoError {
302→            path: source.display().to_string(),
303→            message: "Failed to allocate copyfile state".to_string(),
304→        });
305→    }
306→
307→    // Set up progress callback if context provided
308→    if let Some(ctx) = context {
309→        unsafe {
310→            // Set callback function
311→            let callback_ptr = copy_progress_callback as CopyfileCallback as *const c_void;
312→            copyfile_state_set(state, COPYFILE_STATE_STATUS_CB, callback_ptr);
313→
314→            // Set context pointer
315→            let ctx_ptr = ctx as *const CopyProgressContext as *const c_void;
316→            copyfile_state_set(state, COPYFILE_STATE_STATUS_CTX, ctx_ptr);
317→        }
318→    }
319→
320→    // Perform the copy
321→    log::info!(
322→        "copyfile: starting copy from {} to {} (flags={:#x})",
323→        source.display(),
324→        destination.display(),
325→        flags
326→    );
327→    let result = unsafe { copyfile(src_cstring.as_ptr(), dst_cstring.as_ptr(), state, flags) };
328→    log::info!("copyfile: completed with result={}", result);
329→
330→    // Free state
331→    unsafe {
332→        copyfile_state_free(state);
333→    }
334→
335→    if result == 0 {
336→        Ok(())
337→    } else {
338→        // Check if cancelled
339→        if let Some(ctx) = context
340→            && ctx.cancelled.load(Ordering::Relaxed)
341→        {
342→            return Err(WriteOperationError::Cancelled {
343→                message: "Operation cancelled by user".to_string(),
344→            });
345→        }
346→
347→        // Get the actual error
348→        let err = std::io::Error::last_os_error();
349→        Err(map_io_error_with_path(err, source, destination))
350→    }
351→}
