375→/// Copies a symlink without following it.
376→pub fn copy_symlink(source: &Path, destination: &Path) -> Result<(), WriteOperationError> {
377→    let target = std::fs::read_link(source).map_err(|e| WriteOperationError::IoError {
378→        path: source.display().to_string(),
379→        message: format!("Failed to read symlink: {}", e),
380→    })?;
381→
382→    std::os::unix::fs::symlink(&target, destination).map_err(|e| WriteOperationError::IoError {
383→        path: destination.display().to_string(),
384→        message: format!("Failed to create symlink: {}", e),
385→    })?;
386→
387→    Ok(())
388→}
