394→/// Converts a Path to a CString for FFI.
395→fn path_to_cstring(path: &Path) -> Result<CString, WriteOperationError> {
396→    let path_str = path.to_str().ok_or_else(|| WriteOperationError::IoError {
397→        path: path.display().to_string(),
398→        message: "Path contains invalid UTF-8".to_string(),
399→    })?;
400→
401→    CString::new(path_str).map_err(|_| WriteOperationError::IoError {
402→        path: path.display().to_string(),
403→        message: "Path contains null byte".to_string(),
404→    })
405→}
406→
407→/// Maps an IO error to a WriteOperationError with path context.
408→fn map_io_error_with_path(err: std::io::Error, source: &Path, destination: &Path) -> WriteOperationError {
409→    match err.kind() {
410→        std::io::ErrorKind::NotFound => WriteOperationError::SourceNotFound {
411→            path: source.display().to_string(),
412→        },
413→        std::io::ErrorKind::PermissionDenied => WriteOperationError::PermissionDenied {
414→            path: destination.display().to_string(),
415→            message: format!("Cannot write to {}: permission denied", destination.display()),
416→        },
417→        std::io::ErrorKind::AlreadyExists => WriteOperationError::DestinationExists {
418→            path: destination.display().to_string(),
419→        },
420→        _ => {
421→            // Check for disk full (ENOSPC = 28 on macOS)
422→            if let Some(os_err) = err.raw_os_error()
423→                && os_err == 28
424→            {
425→                // ENOSPC - we don't have exact space info here, so use 0
426→                return WriteOperationError::InsufficientSpace {
427→                    required: 0,
428→                    available: 0,
429→                    volume_name: None,
430→                };
431→            }
432→            WriteOperationError::IoError {
433→                path: source.display().to_string(),
434→                message: err.to_string(),
435→            }
436→        }
437→    }
438→}
