  1→//! Copy strategy selection for file operations.
  2→//!
  3→//! Encapsulates the decision of which copy method to use:
  4→//! - Network filesystems: chunked copy for responsive cancellation
  5→//! - Safe overwrite needed: temp file + rename pattern
  6→//! - macOS: native copyfile(3) with APFS clonefile support
  7→//! - Linux: copy_file_range(2) with reflink support on btrfs/XFS
  8→//! - Other platforms: std::fs::copy fallback
  9→
 10→#[cfg(not(any(target_os = "macos", target_os = "linux")))]
 11→use std::fs;
 12→use std::path::Path;
 13→use std::sync::Arc;
 14→use std::sync::atomic::AtomicBool;
 15→
